                    dlg.AcceptButton = btnOK;              // EnterМќДЅЗЂ
                }
                // --- Yes/NoАДХЅ ---
                else if (buttons == MessageBoxButtons.YesNo)
                {
                    int btnGroupW = btnW * 2 + btnGap;     // АДХЅзщзмПэЖШ = СНИіАДХЅ + МфОр
