                    $"MediaInfo ЙІФмЫЕУїЃК\n" +
                    $"? ЬсИпЗжБцТЪМьВтОЋЖШ\n" +
                    $"? жЇГжИќЖрЪгЦЕИёЪННтЮі\n" +
                    $"? ВЙГф FFmpeg ЮоЗЈЪЖБ№ЕФБрТы\n\n" +
                    $"ЪЧЗёЯТдиАВзА MediaInfo зщМўЃП";

                var dr = DarkMessageBox.Show(this, message, "зщМўЬсЪО", MessageBoxButtons.YesNo, MessageBoxIcon.Information);
                if (dr == DialogResult.Yes)
                {
                    bool ok = await DownloadMediaInfoAsync(this);
