            // ========== ЦСФЛЗжБцТЪздЪЪгІ ==========
            // ИљОнЦСФЛЙЄзїЧјЖЏЬЌМЦЫуДАПкДѓаЁЃЌШЗБЃФкШнЭъећЯдЪО
            Rectangle screenWorkArea = Screen.GetWorkingArea(this);
            int screenWidth = screenWorkArea.Width;
            int screenHeight = screenWorkArea.Height;

            // ПЈЦЌФкШнЫљашИпЖШЃЈDPIЫѕЗХКѓЃЉ
            int scrollTopPad = SY(20);        // ЙіЖЏШнЦїЖЅВПФкБпОр
            int scrollBottomPad = SY(8);      // ЙіЖЏШнЦїЕзВПФкБпОрЃЈМѕЩйСєАзЃЉ
            int scrollRightPad = SX(20);      // ЙіЖЏШнЦїгвВрФкБпОрЃЈВЙГЅЙіЖЏЬѕПэЖШЃЌЪЙПЈЦЌзѓгвСєАзЖдГЦЃЉ
            int cardStartY = SY(15);          // ЕквЛИіПЈЦЌЕФЦ№ЪМYзјБъ
            int engineCardH = SY(105);        // МьВтв§ЧцПЈЦЌ
            int perfCardH = SY(125);          // адФмЩшжУПЈЦЌЃЈ2ааВМОжЃЉ
            int funcCardH = SY(270);          // ЙІФмПЊЙиПЈЦЌЃЈдіМгСЫЫбЫїЙІФмПЊЙиЃЉ
            int customCardH = SY(130);        // ИіадЛЏПЈЦЌЃЈМѕЩйЕзВПСєАзЃЉ
            int cardGap = SY(12);             // ПЈЦЌМфОр
            int btnPanelH = SY(65);           // ЕзВПАДХЅУцАхЃЈМѕЩйИпЖШЃЉ
            // ФЌШЯЙІФмПЊЙиПЈЦЌвўВиЪБЕФФкШнИпЖШЃЈ3ИіПЈЦЌЃЌ2ИіМфОрЃЉ
            int contentTotalH = cardStartY + engineCardH + perfCardH + customCardH + cardGap * 2 + scrollBottomPad;
            int requiredHeight = scrollTopPad + contentTotalH + btnPanelH;

            // ДАПкДѓаЁЃКШЁЫљашИпЖШКЭЦСФЛ95%ЕФНЯаЁжЕЃЌЕЋжСЩйФмШнФЩФкШн
