        /// <summary>
        /// ЕїгУЖРСЂUpdaterЩ§МЖЦїИќаТ
        /// </summary>
        private void StartUpdater(string downloadUrl, string md5 = "")
        {
            string mainExe = Application.ExecutablePath;
            string updaterPath = Path.Combine(Application.StartupPath, "Updater.exe");

            if (!File.Exists(updaterPath))
            {
                DarkMessageBox.Show(this, "Щ§МЖГЬађ Updater.exe ВЛДцдкЃЌЮоЗЈНјааздЖЏИќаТЁЃ\nЧыШЗБЃ Updater.exe гыжїГЬађдкЭЌвЛФПТМЁЃ", "ИќаТЪЇАм", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                return;
            }

            try
            {
                string args = $"\"{mainExe}\" \"{downloadUrl}\" \"{md5}\"";
                var proc = new System.Diagnostics.ProcessStartInfo(updaterPath, args);
                System.Diagnostics.Process.Start(proc);
                Application.Exit();
            }
            catch (Exception ex)
            {
                DarkMessageBox.Show(this, "ЦєЖЏЩ§МЖГЬађЪЇАмЃК" + ex.Message, "ИќаТЪЇАм", MessageBoxButtons.OK, MessageBoxIcon.Error);
            }
        }

        /// <summary>
        /// МьВщШэМўИќаТ
        /// </summary>
        private async void CheckForUpdate()
        {
            string updateUrl = "https://cdn.jsdelivr.net/gh/281761526/IPTVLiveChecker@master/update.json";
            string currentVersion = "v1.0-beta";

            try
            {
                using (var http = new System.Net.Http.HttpClient())
                {
                    http.Timeout = TimeSpan.FromSeconds(10);
                    http.DefaultRequestHeaders.Add("Cache-Control", "no-cache");
                    string json = await http.GetStringAsync(updateUrl).ConfigureAwait(true);

                    var serializer = new JavaScriptSerializer();
                    var jsonObj = serializer.Deserialize<Dictionary<string, object>>(json);

                    if (jsonObj == null)
                    {
                        DarkMessageBox.Show(this, "ИќаТХфжУИёЪНДэЮѓ", "ИќаТДэЮѓ", MessageBoxButtons.OK, MessageBoxIcon.Error);
                        return;
                    }

                    int localVersionCode = 100;
                    string latestVersion = jsonObj.ContainsKey("latestVersion") ? jsonObj["latestVersion"]?.ToString() ?? "" : "";
                    string downloadUrl = jsonObj.ContainsKey("downloadUrl") ? jsonObj["downloadUrl"]?.ToString() ?? "" : "";
                    string md5Checksum = jsonObj.ContainsKey("md5Checksum") ? jsonObj["md5Checksum"]?.ToString() ?? "" : "";
                    int remoteVersionCode = 0;
                    if (jsonObj.ContainsKey("versionCode"))
                        int.TryParse(jsonObj["versionCode"]?.ToString(), out remoteVersionCode);

                    bool isForceUpdate = false;
                    if (jsonObj.ContainsKey("isForceUpdate"))
                        bool.TryParse(jsonObj["isForceUpdate"]?.ToString(), out isForceUpdate);

                    string changelog = "";
                    if (jsonObj.ContainsKey("changelog") && jsonObj["changelog"] is System.Collections.ArrayList logList)
                    {
                        foreach (var item in logList)
                            changelog += "\u2022 " + item?.ToString() + "\n";
                    }

                    bool hasUpdate = remoteVersionCode > localVersionCode;
                    if (hasUpdate)
                    {
                        string updateNotice = jsonObj.ContainsKey("updateNotice") ? jsonObj["updateNotice"]?.ToString() ?? "" : "";
                        string msg = $"ЗЂЯжаТАцБОЃК{latestVersion}\n\n" +
                                     $"ЕБЧААцБОЃК{currentVersion}\n\n" +
                                     $"ИќаТФкШнЃК\n{changelog}\n" +
                                     (string.IsNullOrEmpty(updateNotice) ? "" : $"ЫЕУїЃК{updateNotice}\n\n") +
                                     (isForceUpdate ? "ДЫИќаТЮЊЧПжЦИќаТЃЌБиаыЩ§МЖКѓВХФмМЬајЪЙгУЁЃ" : "ЪЧЗёСЂМДИќаТЃП");

                        if (isForceUpdate)
                        {
                            DarkMessageBox.Show(this, msg, "ЧПжЦИќаТ", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                            StartUpdater(downloadUrl, md5Checksum);
                        }
                        else
                        {
                            var result = DarkMessageBox.Show(this, msg, "ЗЂЯжаТАцБО", MessageBoxButtons.YesNo, MessageBoxIcon.Information);
                            if (result == DialogResult.Yes)
                                StartUpdater(downloadUrl, md5Checksum);
                        }
                    }
                    else
                    {
                        DarkMessageBox.Show(this, $"ЕБЧАвбЪЧзюаТАцБОЃЁ\n\nАцБОЃК{currentVersion}", "МьВщИќаТ", MessageBoxButtons.OK, MessageBoxIcon.Information);
                    }
                }
            }
            catch (Exception ex)
            {
                DarkMessageBox.Show(this, "МьВщИќаТЪЇАмЃК" + ex.Message, "ИќаТДэЮѓ", MessageBoxButtons.OK, MessageBoxIcon.Error);
            }
        }
        
        
        /// <summary>
        /// ЦєЖЏЧАЯдЪОУтд№ЩљУїЖдЛАПђЃЈдкжїДАПкЯдЪОжЎЧАЕїгУЃЉ
        /// </summary>
        /// <returns>гУЛЇЪЧЗёЭЌвтЬѕПю</returns>
        public bool ShowDisclaimerBeforeStart()
        {
            if (!this.IsHandleCreated)
                this.CreateHandle();

            using (Graphics g = this.CreateGraphics())
                dpiScale = g.DpiX / 96f;

            config.Initialize(dpiScale);
            DarkMessageBox.DpiScale = dpiScale;

            LoadConfig();

            if (disclaimerAgreed && skipDisclaimerPrompt)
                return true;

            return ShowDisclaimerDialog();
        }

