        private bool _showStreamInfoOverlay = false;
        private System.Windows.Forms.Timer _streamInfoOverlayTimer;
        private Form _streamInfoOverlayForm;
        private Label _streamInfoLabel;

        private void StartStreamInfoOverlay()
        {
            try
            {
                StopStreamInfoOverlay();

                _streamInfoOverlayForm = new Form
                {
                    FormBorderStyle = FormBorderStyle.None,
                    ShowInTaskbar = false,
                    TopMost = true,
                    StartPosition = FormStartPosition.Manual,
                    BackColor = Color.Black,
                    TransparencyKey = Color.Black,
                    Visible = false
                };

                _streamInfoLabel = new Label
                {
                    Font = GetFont(SF(7f)),
                    ForeColor = Color.White,
                    BackColor = Color.FromArgb(180, 0, 0, 0),
                    AutoSize = true,
                    Padding = new Padding(6),
                    TextAlign = ContentAlignment.TopLeft,
                    UseCompatibleTextRendering = true,
                    Location = new Point(0, 0)
                };

                _streamInfoOverlayForm.Controls.Add(_streamInfoLabel);
                _streamInfoOverlayForm.Show();

                _streamInfoOverlayForm.KeyPreview = true;
                _streamInfoOverlayForm.KeyDown += (s, e) =>
                {
                    if (e.KeyCode == Keys.Escape)
                    {
                        _showStreamInfoOverlay = false;
                        StopStreamInfoOverlay();
                    }
                };

                _streamInfoOverlayTimer = new System.Windows.Forms.Timer { Interval = 100 };
                _streamInfoOverlayTimer.Tick += (s, e) => UpdateStreamInfoOverlay();
                _streamInfoOverlayTimer.Start();
            }
            catch { }
        }

        private void StopStreamInfoOverlay()
        {
            try
            {
                if (_streamInfoOverlayTimer != null)
                {
                    _streamInfoOverlayTimer.Stop();
                    _streamInfoOverlayTimer.Dispose();
                    _streamInfoOverlayTimer = null;
                }
            }
            catch { }

            try
            {
                if (_streamInfoOverlayForm != null && !_streamInfoOverlayForm.IsDisposed)
                {
                    _streamInfoOverlayForm.Close();
                    _streamInfoOverlayForm.Dispose();
                    _streamInfoOverlayForm = null;
                }
            }
            catch { }
        }

        private void UpdateStreamInfoOverlay()
        {
            try
            {
                if (!_showStreamInfoOverlay)
                {
                    StopStreamInfoOverlay();
                    return;
                }

                if (_streamInfoOverlayForm == null || _streamInfoOverlayForm.IsDisposed || _streamInfoLabel == null || _streamInfoLabel.IsDisposed)
                {
                    StopStreamInfoOverlay();
                    return;
                }

                IntPtr targetHwnd = FindPlayerWindow();
                if (targetHwnd == IntPtr.Zero)
                {
                    _streamInfoOverlayForm.Visible = false;
                    return;
                }

                RECT rect;
                if (!GetWindowRect(targetHwnd, out rect))
                {
                    _streamInfoOverlayForm.Visible = false;
                    return;
                }

                StringBuilder info = new StringBuilder();
                if (!string.IsNullOrEmpty(_currentChannelName)) info.Append($"УћГЦ: {_currentChannelName}\n");
                if (!string.IsNullOrEmpty(_currentFormat)) info.Append($"ИёЪН: {_currentFormat}\n");
                if (!string.IsNullOrEmpty(_currentCodec)) info.Append($"БрТы: {_currentCodec}\n");
                if (!string.IsNullOrEmpty(_currentResolution)) info.Append($"ЗжБцТЪ: {_currentResolution}\n");
                if (!string.IsNullOrEmpty(_currentSar)) info.Append($"SAR: {_currentSar}\n");
                if (!string.IsNullOrEmpty(_currentDar)) info.Append($"DAR: {_currentDar}\n");
                if (!string.IsNullOrEmpty(_currentFps)) info.Append($"жЁТЪ: {_currentFps}\n");
                if (!string.IsNullOrEmpty(_currentPixFmt)) info.Append($"ЯёЫиИёЪН: {_currentPixFmt}\n");
                if (!string.IsNullOrEmpty(_currentLevel)) info.Append($"МЖБ№: {_currentLevel}\n");
                if (!string.IsNullOrEmpty(_currentColorSpace)) info.Append($"ЩЋВЪПеМф: {_currentColorSpace}\n");
                if (!string.IsNullOrEmpty(_currentColorPrimaries)) info.Append($"ЩЋЛљ: {_currentColorPrimaries}\n");
                if (!string.IsNullOrEmpty(_currentColorTransfer)) info.Append($"ДЋЕнКЏЪ§: {_currentColorTransfer}\n");
                if (!string.IsNullOrEmpty(_currentAudioChannels)) info.Append($"ЩљЕР: {_currentAudioChannels}\n");
                if (!string.IsNullOrEmpty(_currentAudioSampleRate)) info.Append($"ВЩбљТЪ: {_currentAudioSampleRate}\n");
                if (!string.IsNullOrEmpty(_currentAudioBitdepth)) info.Append($"ЮЛЩю: {_currentAudioBitdepth}\n");
                if (!string.IsNullOrEmpty(_currentBitrate)) info.Append($"ТыТЪ: {_currentBitrate}\n");
                if (!string.IsNullOrEmpty(_currentDuration)) info.Append($"ЪБГЄ: {_currentDuration}\n");
                if (!string.IsNullOrEmpty(_currentDelay)) info.Append($"бгЪБ: {_currentDelay}\n");
                if (!string.IsNullOrEmpty(_currentTime)) info.Append($"ЪБМф: {_currentTime}\n");
                if (!string.IsNullOrEmpty(_currentSpeed)) info.Append($"ЫйЖШ: {_currentSpeed}\n");
                if (!string.IsNullOrEmpty(_currentFrameCount)) info.Append($"жЁМЦЪ§: {_currentFrameCount}\n");
                if (!string.IsNullOrEmpty(_currentDecodedFrames)) info.Append($"{_currentDecodedFrames}\n");
                if (!string.IsNullOrEmpty(_currentDisplayedFrames)) info.Append($"{_currentDisplayedFrames}\n");
                if (!string.IsNullOrEmpty(_currentBuffer)) info.Append($"ЛКГх: {_currentBuffer}\n");
                if (_droppedFrames > 0) info.Append($"ЖЊжЁ: {_droppedFrames}/{_totalFrames}");

                _streamInfoLabel.Text = info.ToString();
                _streamInfoLabel.Location = new Point(0, 0);

                _streamInfoOverlayForm.Location = new Point(rect.Left + 26, rect.Top + 60);
                _streamInfoOverlayForm.Size = _streamInfoLabel.Size;
                _streamInfoOverlayForm.Visible = true;
            }
            catch
            {
                StopStreamInfoOverlay();
            }
        }

        private IntPtr FindPlayerWindow()
        {
            IntPtr targetHwnd = IntPtr.Zero;

            if (_runningPlayer != null && !_runningPlayer.HasExited)
            {
                uint targetPid = (uint)_runningPlayer.Id;
                EnumWindows((hWnd, lParam) =>
                {
                    if (!IsWindowVisible(hWnd)) return true;
                    uint pid;
                    GetWindowThreadProcessId(hWnd, out pid);
                    if (pid != targetPid) return true;
                    StringBuilder className = new StringBuilder(256);
                    GetClassName(hWnd, className, className.Capacity);
                    string clsName = className.ToString().ToLower();
                    StringBuilder windowTitle = new StringBuilder(512);
                    GetWindowText(hWnd, windowTitle, windowTitle.Capacity);
                    string title = windowTitle.ToString().ToLower();
                    if (clsName.Contains("sdl") || clsName.Contains("ffplay") || 
                        clsName.Contains("potplayer") || clsName.Contains("vlc") || 
                        clsName.Contains("mpv") || clsName.Contains("wxwidgets") ||
                        title.Contains("potplayer") || title.Contains("vlc") || title.Contains("mpv"))
                    {
                        targetHwnd = hWnd;
                        return false;
                    }
                    return true;
                }, IntPtr.Zero);
            }
            else if (previewProcess != null && !previewProcess.HasExited)
            {
                uint targetPid = (uint)previewProcess.Id;
                EnumWindows((hWnd, lParam) =>
                {
                    if (!IsWindowVisible(hWnd)) return true;
                    uint pid;
                    GetWindowThreadProcessId(hWnd, out pid);
                    if (pid != targetPid) return true;
                    StringBuilder className = new StringBuilder(256);
                    GetClassName(hWnd, className, className.Capacity);
                    string clsName = className.ToString().ToLower();
                    StringBuilder windowTitle = new StringBuilder(512);
                    GetWindowText(hWnd, windowTitle, windowTitle.Capacity);
                    string title = windowTitle.ToString().ToLower();
                    if (clsName.Contains("sdl") || clsName.Contains("ffplay") || 
                        clsName.Contains("potplayer") || clsName.Contains("vlc") || 
                        clsName.Contains("mpv") || clsName.Contains("wxwidgets") ||
                        title.Contains("potplayer") || title.Contains("vlc") || title.Contains("mpv"))
                    {
                        targetHwnd = hWnd;
                        return false;
                    }
                    return true;
                }, IntPtr.Zero);
            }

            return targetHwnd;
        }

        /// <summary>
        /// ЙЙНЈжїНчУцUIЃЈЭъећЕФНчУцГѕЪМЛЏШыПкЃЉ
        /// АќКЌДАПкздЪЪгІЁЂжїЬтГѕЪМЛЏЁЂDPIЫѕЗХХфжУЁЂећЬхВМОжНсЙЙДюНЈ
        /// ВМОжНсЙЙЃКЭтВуБпПђШнЦї Ёњ БъЬтРИ(Dock=Top) Ёњ жїФкШнЧј(Dock=Fill)
        /// жїФкШнЧјЃКзѓВрЕМКНРИ Ёњ жаМфВйзїЧј Ёњ гвВрЪ§ОнБэИёЧј
        /// </summary>
        private void BuildUI()
        {
            // ========== жїЬтГѕЪМЛЏ ==========
            if (themePreference == "ЩюЩЋ") theme = AppTheme.Dark;
            else if (themePreference == "ИњЫцЯЕЭГ") theme = AppTheme.GetAutoTheme();
            else theme = AppTheme.Light;

            // ========== ДАПкЛљДЁХфжУ ==========
            this.Text = "";                                    // ЧхПеФЌШЯБъЬтЃЈЪЙгУздЖЈвхБъЬтРИЃЉ
            this.AutoScaleMode = AutoScaleMode.None;           // НћгУЯЕЭГздЖЏЫѕЗХЃЈЪЙгУздЖЈвхDPIЫѕЗХЃЉ
            // ЛёШЁЕБЧАDPIЫѕЗХБШР§ЃЈ96dpiЮЊ100%ЫѕЗХЛљзМЃЉ
            using (Graphics g = this.CreateGraphics())
                dpiScale = g.DpiX / 96f;
            config.Initialize(dpiScale);
            DarkMessageBox.DpiScale = dpiScale;

            // ========== ДАПкДѓаЁздЪЪгІЃЈИљОнЦСФЛЗжБцТЪЃЉ ==========
            // ДАПкДѓаЁ = ЦСФЛЙЄзїЧјЕФ88%ЃЌзюаЁ1280x800ЃЌШЗБЃдкВЛЭЌЗжБцТЪЯТЖМФмЭъећЯдЪО
            int screenW = Screen.PrimaryScreen.WorkingArea.Width;
            int screenH = Screen.PrimaryScreen.WorkingArea.Height;
            int winW = Math.Max(1280, (int)(screenW * 0.88)); // ДАПкПэЖШ
            int winH = Math.Max(800, (int)(screenH * 0.88));  // ДАПкИпЖШ
            this.Size = new Size(winW, winH);
            this.StartPosition = FormStartPosition.Manual;     // ЪжЖЏЖЈЮЛЃЈОгжаЯдЪОЃЉ
            this.Location = new Point(
                (screenW - winW) / 2,                          // ЫЎЦНОгжа
                (screenH - winH) / 2                           // ДЙжБОгжа
            );
            this.Font = GetFont(SF(11f));                      // ШЋОжзжЬхЃЈYaHei 11pt * DPIЫѕЗХЃЉ
            this.MinimumSize = new Size(SX(900), SY(600));     // ДАПкзюаЁГпДчЃЈ900x600 * DPIЫѕЗХЃЉ
            this.BackColor = theme.Border;                     // ДАПкБГОАЩЋЃЈБпПђЩЋЃЉ

            // ========== ЭтВуБпПђШнЦї ==========
            // [зїгУ] ЪЕЯжЯИБпПђаЇЙћЃЌpadding=1pxЪЙФкШнгыДАПкБпдЕга1pxМфИє
            outerWrap = new Panel
            {
                Dock = DockStyle.Fill,
                BackColor = theme.Border,
                Padding = new Padding(1)
            };
            this.Controls.Add(outerWrap);

            // ========== здЖЈвхБъЬтРИ ==========
            CreateTitleBar();

            // ================================================================
            //  WinForms DockВМОжЙцдђ: Dock=LeftЪБ,зюКѓAddЕФПиМўдкзюзѓБп
            //  ФПБъЫГађ(ДгзѓЕНгв): navPanel Ёњ navSep Ёњ actionArea Ёњ actionSep Ёњ mainArea(Fill)
            // ================================================================

            // ========== гвВржїЪ§ОнЧј(Dock=Fill,зюЯШAdd) ==========
            // [ЮЛжУ] ЬюГфЪЃгрПеМф [БГОА] жїЬтДЮвЊБГОАЩЋ [ЙІФм] АќКЌЫбЫїРИКЭЪ§ОнБэИё
            mainArea = new Panel
            {
                Dock = DockStyle.Fill,
                BackColor = theme.BgAlt
            };
            mainArea.Resize += (s, e) =>
            {
                UpdateScrollBarTheme(mainArea); // ДАПкДѓаЁБфЛЏЪБИќаТЙіЖЏЬѕжїЬт
            };

            // ========== Ъ§ОнБэИёШнЦї(Dock=Fill,дкmainAreaФкзюЯШAdd) ==========
            // [ЮЛжУ] ЬюГфmainAreaЪЃгрПеМф [БГОА] жїЬтДЮвЊБГОАЩЋ [ЙІФм] АќКЌDataGridViewКЭПезДЬЌУцАх
            gridContainerRef = new Panel
            {
                Dock = DockStyle.Fill,
                BackColor = theme.BgAlt
            };

            // ========== Ъ§ОнБэИё(DataGridView) ==========
            // [ЮЛжУ] ЬюГфgridContainerRef [зжЬх] YaHei 6.7pt * DPIЫѕЗХ [ааИп] 36px * DPIЫѕЗХ
            // [ЙІФм] ЯдЪОЦЕЕРСаБэЃЌжЇГжЫЋЛїВЅЗХЁЂБрМ­УћГЦЁЂХХађЁЂХњСПВйзї
            dgvData = new DataGridView();
            dgvData.Dock = DockStyle.Fill;
            dgvData.AutoSizeColumnsMode = DataGridViewAutoSizeColumnsMode.Fill; // СаздЖЏЬюГф
            dgvData.BackgroundColor = theme.BgAlt;                            // БГОАЩЋ
            dgvData.RowHeadersVisible = false;                                 // вўВиааЭЗ
            dgvData.SelectionMode = DataGridViewSelectionMode.FullRowSelect;   // ећаабЁдё
            dgvData.ReadOnly = false;                                          // дЪаэБрМ­
            dgvData.AllowUserToAddRows = false;                                // НћжЙгУЛЇЬэМгаа
            dgvData.AllowUserToDeleteRows = false;                             // НћжЙгУЛЇЩОГ§аа
            dgvData.AllowUserToResizeColumns = false;                          // НћжЙгУЛЇЕїећСаПэ
            dgvData.AllowUserToResizeRows = false;                             // НћжЙгУЛЇЕїећааИп
            dgvData.AllowUserToOrderColumns = false;                           // НћжЙгУЛЇХХађСа
            dgvData.EditMode = DataGridViewEditMode.EditOnF2;                  // АДF2БрМ­
            dgvData.Font = GetFont(SF(6.7f));                                  // ЕЅдЊИёзжЬхЃЈ6.7pt * DPIЫѕЗХЃЉ
            dgvData.RowTemplate.Height = SY(42);                               // ааИпЃЈ42px * DPIЫѕЗХЃЉ
            // АѓЖЈЪТМў
            dgvData.CellDoubleClick += DgvData_CellDoubleClick;                // ЫЋЛїВЅЗХ
            dgvData.CellEndEdit += DgvData_CellEndEdit;                        // БрМ­НсЪј
            // ПьНнМќЃКCtrl+AШЋбЁЃЌCtrl+Shift+CИДжЦЫљгаСДНг
            dgvData.KeyDown += (s, e) =>
            {
                if (e.Control && e.KeyCode == Keys.A)
                {
                    SelectAllRows();
                    e.SuppressKeyPress = true;
                }
                else if (e.Control && e.Shift && e.KeyCode == Keys.C)
                {
                    CopyAllLinks();
                    e.SuppressKeyPress = true;
                }
            };
            // бљЪНХфжУ
            dgvData.EnableHeadersVisualStyles = false;                         // НћгУЯЕЭГФЌШЯБэЭЗбљЪН
            dgvData.GridColor = theme.Border;                                  // ЭјИёЯпбеЩЋ
            dgvData.BorderStyle = BorderStyle.None;                            // ЮоБпПђ
            dgvData.CellBorderStyle = DataGridViewCellBorderStyle.SingleVertical; // НіЯдЪОДЙжБЗжИєЯп
            dgvData.ColumnHeadersVisible = true;                               // ЯдЪОБэЭЗ
            dgvData.ColumnHeadersHeightSizeMode = DataGridViewColumnHeadersHeightSizeMode.DisableResizing; // ЙЬЖЈБэЭЗИпЖШ
            dgvData.ColumnHeadersHeight = SY(36);                              // БэЭЗИпЖШЃЈ36px * DPIЫѕЗХЃЉ
            dgvData.ColumnHeadersBorderStyle = DataGridViewHeaderBorderStyle.None; // БэЭЗЮоБпПђ
            dgvData.DefaultCellStyle.SelectionBackColor = theme.SelectRow;    // бЁжаааБГОАЩЋ
            dgvData.DefaultCellStyle.SelectionForeColor = theme.SelectRowText; // бЁжаааЮФзжЩЋ
            dgvData.RowTemplate.Height = SY(36);                               // ааИпЃЈ36px * DPIЫѕЗХЃЉ

            // ========== БэЭЗбљЪН ==========
            // [БГОА] жїЬтБэЭЗБГОАЩЋ [ЮФзж] ДЮвЊЮФзжЩЋ [зжЬх] YaHei 9pt * DPIЫѕЗХ [ЖдЦы] зѓЖдЦы
            DataGridViewCellStyle headerStyle = new DataGridViewCellStyle();
            headerStyle.BackColor = theme.HeaderBg;        // БэЭЗБГОАЩЋ
            headerStyle.ForeColor = theme.TextSecondary;   // БэЭЗЮФзжЩЋ
            headerStyle.Font = GetFont(SF(9f));            // БэЭЗзжЬхЃЈ9pt * DPIЫѕЗХЃЉ
            headerStyle.Alignment = DataGridViewContentAlignment.MiddleLeft; // зѓЖдЦы
            headerStyle.Padding = new Padding(SX(10), 0, 0, 0); // зѓФкБпОрЃЈ10px * DPIЫѕЗХЃЉ
            headerStyle.SelectionBackColor = theme.HeaderBg;    // бЁжаЪББГОАЩЋВЛБф
            headerStyle.SelectionForeColor = theme.TextSecondary; // бЁжаЪБЮФзжЩЋВЛБф
            dgvData.ColumnHeadersDefaultCellStyle = headerStyle;

            // ========== аабљЪН ==========
            // [БГОА] жїЬтБэУцЩЋ [ЮФзж] жїЮФзжЩЋ [зжЬх] YaHei 6.7pt * DPIЫѕЗХ [ФкБпОр] зѓ10pxгв6px
            DataGridViewCellStyle rowStyle = new DataGridViewCellStyle();
            rowStyle.BackColor = theme.Surface;           // ааБГОАЩЋ
            rowStyle.ForeColor = theme.TextPrimary;       // ааЮФзжЩЋ
            rowStyle.SelectionBackColor = theme.SelectRow; // бЁжаааБГОАЩЋ
            rowStyle.SelectionForeColor = theme.SelectRowText; // бЁжаааЮФзжЩЋ
            rowStyle.Padding = new Padding(SX(10), SY(0), SX(6), SY(0)); // ФкБпОрЃЈзѓ10px,гв6px * DPIЫѕЗХЃЉ
            rowStyle.Font = GetFont(SF(6.7f));            // аазжЬхЃЈ6.7pt * DPIЫѕЗХЃЉ
            dgvData.RowsDefaultCellStyle = rowStyle;
            // НЛЬцаабљЪНЃЈгыЦеЭЈааЯрЭЌЃЌЮоАпТэЮЦаЇЙћЃЉ
            DataGridViewCellStyle altStyle = new DataGridViewCellStyle();
            altStyle.BackColor = theme.Surface;
            altStyle.ForeColor = theme.TextPrimary;
            altStyle.SelectionBackColor = theme.SelectRow;
            altStyle.SelectionForeColor = theme.SelectRowText;
            altStyle.Padding = new Padding(SX(10), SY(0), SX(6), SY(0));
            altStyle.Font = GetFont(SF(6.7f));
            dgvData.AlternatingRowsDefaultCellStyle = altStyle;

            // ========== СаЖЈвхЃЈ8СаЃЉ ==========
            // [УћГЦ] ПЩБрМ­ [СДНг] жЛЖС/ConsolasзжЬх [ЙщЪєЕи] жЛЖС [ЗжБцТЪ] жЛЖС
            // [ЯьгІЫйЖШ] вЉЭшбљЪН/жЛЖС [Зжзщ] жЛЖС [зДЬЌ] вЉЭшбљЪН/жЛЖС [Вйзї] здЛцЫЋАДХЅ/жЛЖС
            dgvData.Columns.Add("colName", "УћГЦ");       // ЦЕЕРУћГЦЃЈПЩБрМ­ЃЉ
            dgvData.Columns.Add("colUrl", "СДНг");        // ВЅЗХСДНгЃЈжЛЖСЃЌConsolasзжЬхЃЉ
            dgvData.Columns.Add("colLocation", "ЙщЪєЕи"); // ЙщЪєЕиаХЯЂ
            dgvData.Columns.Add("colResolution", "ЗжБцТЪ"); // ЪгЦЕЗжБцТЪ
            dgvData.Columns.Add("colSpeed", "ЯьгІЫйЖШ");   // ЯьгІЫйЖШЃЈвЉЭшбљЪНЃЉ
            dgvData.Columns.Add("colGroup", "Зжзщ");      // ЗжзщаХЯЂ
            dgvData.Columns.Add("colStatus", "зДЬЌ");      // зДЬЌЃЈвЉЭшбљЪНЃЉ
            dgvData.Columns.Add("colAction", "Вйзї");      // ВйзїСаЃЈздЛцВЅЗХ/ИДжЦАДХЅЃЉ

            // ========== БэИёЪТМўАѓЖЈ ==========
            dgvData.CellClick += DgvData_CellClick;                          // ЕЅдЊИёЕуЛїЃЈВйзїАДХЅЃЉ
            dgvData.ColumnHeaderMouseClick += DgvData_ColumnHeaderMouseClick; // БэЭЗЕуЛїЃЈХХађЃЉ
            dgvData.CellPainting += DgvData_CellPainting;                    // ЕЅдЊИёздЛцЃЈвЉЭшЁЂАДХЅЃЉ
            dgvData.CellFormatting += DgvData_CellFormatting;                // ЕЅдЊИёИёЪНЛЏ
            dgvData.CellMouseMove += DgvData_CellMouseMove;                  // ЪѓБъвЦЖЏЃЈаќЭЃАДХЅЃЉ
            dgvData.CellMouseDown += DgvData_CellMouseDown;                  // ЪѓБъАДЯТ
            dgvData.CellMouseUp += DgvData_CellMouseUp;                      // ЪѓБъЪЭЗХ
            dgvData.ShowCellToolTips = true;                                 // ЯдЪОЕЅдЊИёЙЄОпЬсЪО
            // ЙЄОпЬсЪОЃКЕБЕЅдЊИёФкШнЙ§ГЄЪБЯдЪОЭъећФкШн
            dgvData.CellToolTipTextNeeded += (s, e) =>
            {
                if (e.RowIndex >= 0 && e.ColumnIndex >= 0)
                {
                    string colName = dgvData.Columns[e.ColumnIndex].Name;
                    if (colName == "colName" || colName == "colUrl" || colName == "colLocation" || colName == "colResolution" || colName == "colGroup")
                    {
                        var val = dgvData.Rows[e.RowIndex].Cells[e.ColumnIndex].Value?.ToString() ?? "";
                        if (!string.IsNullOrWhiteSpace(val)) e.ToolTipText = val;
                    }
                }
            };
            // ЪѓБъРыПЊБэИёЪБжижУаќЭЃзДЬЌ
            dgvData.MouseLeave += (s, e) => { if (_hoverRow != -1) { _hoverRow = -1; _hoverBtn = -1; dgvData.Invalidate(); } };

            // ========== СаПэШЈжиХфжУЃЈFillWeightЃЉ ==========
            // ШЈжизмКЭ = 323ЃЌСДНгСаеМзюДѓБШжиЃЈ160/323 Ёж 50%ЃЉ
            dgvData.Columns["colName"].FillWeight = 15;       // УћГЦСаШЈжи
            dgvData.Columns["colUrl"].FillWeight = 160;      // СДНгСаШЈжиЃЈзюПэЃЉ
            dgvData.Columns["colLocation"].FillWeight = 35;   // ЙщЪєЕиСаШЈжи
            dgvData.Columns["colResolution"].FillWeight = 22; // ЗжБцТЪСаШЈжи
            dgvData.Columns["colSpeed"].FillWeight = 25;      // ЯьгІЫйЖШСаШЈжи
            dgvData.Columns["colGroup"].FillWeight = 18;      // ЗжзщСаШЈжи
            dgvData.Columns["colStatus"].FillWeight = 20;     // зДЬЌСаШЈжи
            dgvData.Columns["colAction"].FillWeight = 28;     // ВйзїСаШЈжи

            // ========== СазюаЁПэЖШХфжУЃЈШЗБЃФкШнЭъећЯдЪОЃЉ ==========
            // [СДНгСа] зюаЁ600pxЃЈЗРжЙURLБЛНиЖЯЃЉ[ВйзїСа] зюаЁ20pxЃЈЫЋАДХЅПеМфЃЉ
            dgvData.Columns["colName"].MinimumWidth = SX(12);       // УћГЦСазюаЁПэЖШ
            dgvData.Columns["colUrl"].MinimumWidth = SX(600);      // СДНгСазюаЁПэЖШЃЈШЗБЃURLЭъећЃЉ
            dgvData.Columns["colLocation"].MinimumWidth = SX(20);   // ЙщЪєЕиСазюаЁПэЖШ
            dgvData.Columns["colResolution"].MinimumWidth = SX(15); // ЗжБцТЪСазюаЁПэЖШ
            dgvData.Columns["colSpeed"].MinimumWidth = SX(20);      // ЯьгІЫйЖШСазюаЁПэЖШ
            dgvData.Columns["colGroup"].MinimumWidth = SX(18);      // ЗжзщСазюаЁПэЖШ
            dgvData.Columns["colStatus"].MinimumWidth = SX(18);     // зДЬЌСазюаЁПэЖШ
            dgvData.Columns["colAction"].MinimumWidth = SX(20);     // ВйзїСазюаЁПэЖШЃЈЫЋАДХЅЃЉ

            // ========== СаЖдЦыЗНЪНХфжУ ==========
            // [ФЌШЯ] ОгжаЖдЦы [УћГЦ/СДНг/ЙщЪєЕи/ЗжБцТЪ/Зжзщ] зѓЖдЦы [ЯьгІЫйЖШ/зДЬЌ/Вйзї] ОгжаЖдЦы
            foreach (DataGridViewColumn col in dgvData.Columns)
            {
                col.SortMode = DataGridViewColumnSortMode.Programmatic; // БрГЬЪНХХађ
                col.DefaultCellStyle.Alignment = DataGridViewContentAlignment.MiddleCenter; // ФЌШЯОгжа
            }
            // ЮФБОСазѓЖдЦы
            dgvData.Columns["colName"].DefaultCellStyle.Alignment = DataGridViewContentAlignment.MiddleLeft;
            dgvData.Columns["colUrl"].DefaultCellStyle.Alignment = DataGridViewContentAlignment.MiddleLeft;
            dgvData.Columns["colLocation"].DefaultCellStyle.Alignment = DataGridViewContentAlignment.MiddleLeft;
            dgvData.Columns["colResolution"].DefaultCellStyle.Alignment = DataGridViewContentAlignment.MiddleLeft;
            dgvData.Columns["colGroup"].DefaultCellStyle.Alignment = DataGridViewContentAlignment.MiddleLeft;
            // вЉЭшЃЈЯьгІЫйЖШЁЂзДЬЌЃЉКЭАДХЅЃЈВйзїЃЉБЃГжОгжа
            dgvData.Columns["colSpeed"].DefaultCellStyle.Alignment = DataGridViewContentAlignment.MiddleCenter;
            dgvData.Columns["colStatus"].DefaultCellStyle.Alignment = DataGridViewContentAlignment.MiddleCenter;
            dgvData.Columns["colAction"].DefaultCellStyle.Alignment = DataGridViewContentAlignment.MiddleCenter;

            // ========== СажЛЖСХфжУ ==========
            // [УћГЦ] ПЩБрМ­ЃЈдЪаэгУЛЇаоИФЦЕЕРУћГЦЃЉ[ЦфЫћ] жЛЖСЃЈЪ§ОнгЩГЬађЩњГЩЃЉ
            dgvData.Columns["colName"].ReadOnly = false;          // УћГЦСаПЩБрМ­
            dgvData.Columns["colUrl"].ReadOnly = true;            // СДНгСажЛЖС
            dgvData.Columns["colUrl"].DefaultCellStyle.Font = new Font("Consolas", SF(6.7f)); // СДНгСаЪЙгУЕШПэзжЬх
            dgvData.Columns["colLocation"].ReadOnly = true;       // ЙщЪєЕиСажЛЖС
            dgvData.Columns["colResolution"].ReadOnly = true;     // ЗжБцТЪСажЛЖС
            dgvData.Columns["colSpeed"].ReadOnly = true;          // ЯьгІЫйЖШСажЛЖС
            dgvData.Columns["colGroup"].ReadOnly = true;          // ЗжзщСажЛЖС
            dgvData.Columns["colStatus"].ReadOnly = true;         // зДЬЌСажЛЖС
            dgvData.Columns["colAction"].ReadOnly = true;         // ВйзїСажЛЖСЃЈздЛцАДХЅЃЉ

            // ФЌШЯАДУћГЦЩ§ађХХађ
            sortedColumn = "colName";
            sortDirection = SortOrder.Ascending;

            gridContainerRef.Controls.Add(dgvData);

            // ========== ПезДЬЌУцАхЃЈЮоЪ§ОнЪБЯдЪОЃЉ ==========
            // [ЮЛжУ] ОгжаЯдЪО [ДѓаЁ] 140x110px * DPIЫѕЗХ [ФкШн] ЭМБъ + "ЮоаЇеО"ЬсЪОЮФзж
            emptyStatePanel = new Panel
            {
                BackColor = Color.Transparent,  // ЭИУїБГОА
                Size = new Size(SX(140), SY(110)) // УцАхДѓаЁЃЈ140x110px * DPIЫѕЗХЃЉ
            };

            // ПезДЬЌЭМБъЃЈздЖЈвхЛцжЦЕчЪгЙиБеЭМБъЃЉ
            PictureBox emptyIconBox = new PictureBox
            {
                Size = new Size(SX(56), SY(56)),      // ЭМБъДѓаЁЃЈ56x56px * DPIЫѕЗХЃЉ
                Location = new Point(SX(42), SY(0)),   // ЭМБъЮЛжУЃЈЫЎЦНОгжаЃЉ
                BackColor = Color.Transparent,
                SizeMode = PictureBoxSizeMode.CenterImage
            };
            emptyIconBox.Paint += EmptyIcon_Paint; // АѓЖЈздЖЈвхЛцжЦЪТМў

            // ПезДЬЌЮФзжЬсЪО
            emptyLabel = new Label
            {
                Text = "ЮоаЇеО",                        // ЬсЪОЮФзж
                Font = GetFont(SF(11f)),               // зжЬхЃЈ11pt * DPIЫѕЗХЃЉ
                ForeColor = Color.FromArgb(180, 180, 180), // ЛвЩЋЮФзж
                AutoSize = true,                        // здЖЏЕїећДѓаЁ
                TextAlign = ContentAlignment.MiddleCenter // ОгжаЖдЦы
            };

            emptyStatePanel.Controls.Add(emptyIconBox);
            emptyStatePanel.Controls.Add(emptyLabel);
            gridContainerRef.Controls.Add(emptyStatePanel);
            emptyStatePanel.BringToFront(); // жУгкзюЩЯВу

            // ШнЦїДѓаЁБфЛЏЪБжиаТОгжаПезДЬЌУцАх
            gridContainerRef.Resize += (s, e) => CenterEmptyState();

            // ========== ЫбЫїРИ(Dock=Top,дкgridContainerЩЯЗНAdd) ==========
            // [ЮЛжУ] ЖЅВПЭЃПП [ИпЖШ] 38px * DPIЫѕЗХ [БГОА] жїЬтДЮвЊБГОАЩЋ
            // [ФкШн] ЫбЫїБъЧЉ + ЫбЫїПђ + ЗжзщЩИбЁБъЧЉ + ЗжзщЯТР­Пђ
            searchPanelRef = new Panel
            {
                Dock = DockStyle.Top,           // ЖЅВПЭЃПП
                Height = SY(38),                // ИпЖШЃЈ38px * DPIЫѕЗХЃЉ
                BackColor = theme.BgAlt         // БГОАЩЋ
            };

            // ЫбЫїБъЧЉЃЈ"Ыб Ыї :"ЃЉ
            Label lblSearch = new Label
            {
                Text = "Ыб Ыї :",
                Font = GetFont(SF(8.5f)),     // зжЬхЃЈ8.5pt * DPIЫѕЗХЃЉ
                ForeColor = theme.TextPrimary,
                Location = new Point(0, SY(0)),
                AutoSize = true
            };
            lblSearch.Height = SY(26);
            lblSearch.Top = (SY(38) - SY(26)) / 2; // ДЙжБОгжа
            searchPanelRef.Controls.Add(lblSearch);

            // ========== ЗжзщЩИбЁЯТР­ПђЃЈгвВрЃЉ ==========
            // [ШнЦї] 110x26px * DPIЫѕЗХ [ПиМў] DarkComboBoxздЛцдВНЧ
            cboGroupHost = new Panel
            {
                BackColor = theme.BgAlt,
                Visible = false,               // ФЌШЯвўВиЃЈгаЗжзщЪБЯдЪОЃЉ
                Anchor = AnchorStyles.Top | AnchorStyles.Left,
                Location = new Point(0, (SY(38) - SY(26)) / 2), // ДЙжБОгжа
                Size = new Size(110, SY(26))   // ШнЦїДѓаЁЃЈ110x26pxЃЉ
            };
            // здЖЈвхЩюЩЋЯТР­ПђЃЈдВНЧ6pxЃЉ
            DarkComboBox darkCbo = new DarkComboBox
            {
                Font = GetFont(SF(8.5f)),               // зжЬхЃЈ8.5pt * DPIЫѕЗХЃЉ
                Dock = DockStyle.Fill,
                BackColor = theme.Surface,              // БГОАЩЋ
                ForeColor = theme.TextPrimary,          // ЮФзжЩЋ
                BorderColor = theme.Border,             // БпПђЩЋ
                FocusBorderColor = theme.Primary,       // ОлНЙЪББпПђЩЋ
                ItemBackColor = theme.Surface,          // бЁЯюБГОАЩЋ
                ItemSelectedBackColor = theme.BgAlt,    // бЁжабЁЯюБГОАЩЋ
                ItemHoverBackColor = Color.FromArgb(Math.Min(255, theme.Surface.R + 10), Math.Min(255, theme.Surface.G + 10), Math.Min(255, theme.Surface.B + 10)), // аќЭЃбЁЯюБГОАЩЋ
                CornerRadius = 6,                       // дВНЧАыОЖЃЈ6pxЃЉ
                ItemHeight = SY(22)                     // бЁЯюИпЖШЃЈ22px * DPIЫѕЗХЃЉ
            };
            cboGroup = darkCbo;
            cboGroup.Items.Add("ШЋВП");                // ФЌШЯбЁЯю
            cboGroup.SelectedIndex = 0;                // ФЌШЯбЁжа"ШЋВП"
            cboGroup.SelectedIndexChanged += CboGroup_SelectedIndexChanged; // АѓЖЈЗжзщЩИбЁЪТМў
            cboGroupHost.Controls.Add(cboGroup);
            searchPanelRef.Controls.Add(cboGroupHost);

            // ЗжзщЩИбЁБъЧЉЃЈ"Зжзщ:"ЃЉ
            Label lblGroup = new Label
            {
                Text = "Зжзщ:",
                Font = GetFont(SF(8.5f)),     // зжЬхЃЈ8.5pt * DPIЫѕЗХЃЉ
                ForeColor = theme.TextPrimary,
                AutoSize = true,
                Anchor = AnchorStyles.Top | AnchorStyles.Left,
                Visible = false,               // ФЌШЯвўВиЃЈгаЗжзщЪБЯдЪОЃЉ
                TextAlign = ContentAlignment.MiddleRight
            };
            lblGroup.Height = SY(26);
            lblGroup.Top = (SY(38) - SY(26)) / 2; // ДЙжБОгжа
            lblGroupFilter = lblGroup;
            searchPanelRef.Controls.Add(lblGroup);

            // ========== ЫбЫїПђдВНЧШнЦї ==========
            // [ЮЛжУ] (98, ДЙжБОгжа) [ДѓаЁ] 40x26px [БГОА] жїЬтБэУцЩЋ
            // [ФкВП] TextBoxЃЈЮоБпПђЃЉ+ дВНЧБпПђздЛц
            Panel searchBoxHost = new Panel
            {
                Location = new Point(98, (SY(38) - SY(26)) / 2), // ЮЛгкЫбЫїБъЧЉгвВр
                Anchor = AnchorStyles.Top | AnchorStyles.Left,
                Size = new Size(40, SY(26)),                     // ГѕЪМДѓаЁЃЈ40x26pxЃЉ
                BackColor = theme.Surface                        // БГОАЩЋ
            };
            searchBoxHostRef = searchBoxHost;
            searchPanelRef.Controls.Add(searchBoxHost);

            // ЫбЫїЪфШыПђЃЈЮоБпПђЃЌЧЖШыдВНЧШнЦїФкЃЉ
            TextBox txtSearch = new TextBox
            {
                Font = GetFont(SF(8f)),              // зжЬхЃЈ8pt * DPIЫѕЗХЃЉ
                BorderStyle = BorderStyle.None,       // ЮоБпПђЃЈгЩШнЦїЛцжЦдВНЧБпПђЃЉ
                Location = new Point(18, SY(2)),      // ФкВПЦЋвЦЃЈзѓ18px,ЩЯ2pxЃЉ
                Anchor = AnchorStyles.Top | AnchorStyles.Left | AnchorStyles.Right, // зѓгвздЪЪгІ
                Width = searchBoxHost.Width - 20,    // ПэЖШЃЈШнЦїПэЖШ-20pxЃЉ
                Height = SY(18),                     // ИпЖШЃЈ18px * DPIЫѕЗХЃЉ
                Text = "ЪфШыЫбЫїФкШнЃЌАДЯТЛиГЕМќЫбЫї", // еМЮЛЬсЪОЮФзж
                ForeColor = theme.TextSecondary,     // еМЮЛЮФзжбеЩЋЃЈДЮвЊЮФзжЩЋЃЉ
                BackColor = theme.Surface            // БГОАЩЋ
            };
            txtSearchBox = txtSearch;
            searchBoxHost.Controls.Add(txtSearch);

            // вЦГ§ЯТР­ПђЕФЯЕЭГФЌШЯжїЬтбљЪНЃЈЪЙЦфЪЙгУздЖЈвхЛцжЦЃЉ
            cboGroup.HandleCreated += (s, e) =>
            {
                SetWindowTheme(cboGroup.Handle, "", "");
            };

            // ========== ЫбЫїПђНЙЕуДІРэгыдВНЧБпПђЛцжЦ ==========
            bool searchFocus = false; // ЫбЫїПђОлНЙзДЬЌБъжО

            // ЫбЫїПђЛёШЁНЙЕу
            txtSearch.GotFocus += (s, e) =>
            {
                searchFocus = true;
                searchBoxHost.Invalidate(); // ДЅЗЂжиЛцЃЈИќаТБпПђбеЩЋЃЉ
                // ЧхПееМЮЛЬсЪОЮФзжЃЌИФЮЊжїЮФзжЩЋ
                if (txtSearch.Text == "ЪфШыЫбЫїФкШнЃЌАДЯТЛиГЕМќЫбЫї")
                {
                    txtSearch.Text = "";
                    txtSearch.ForeColor = theme.TextPrimary;
                }
            };

            // ЫбЫїПђЪЇШЅНЙЕу
            txtSearch.LostFocus += (s, e) =>
            {
                searchFocus = false;
                searchBoxHost.Invalidate(); // ДЅЗЂжиЛцЃЈЛжИДБпПђбеЩЋЃЉ
                // ЛжИДеМЮЛЬсЪОЮФзжЃЌИФЮЊДЮвЊЮФзжЩЋ
                if (string.IsNullOrWhiteSpace(txtSearch.Text))
                {
                    txtSearch.Text = "ЪфШыЫбЫїФкШнЃЌАДЯТЛиГЕМќЫбЫї";
                    txtSearch.ForeColor = theme.TextSecondary;
                }
            };

            // ЫбЫїПђдВНЧБпПђЛцжЦЃЈОлНЙЪББпПђБфДжБфССЃЉ
            searchBoxHost.Paint += (s, e) =>
            {
                e.Graphics.SmoothingMode = SmoothingMode.AntiAlias; // ПЙОтГн
                Rectangle rect = new Rectangle(0, 0, searchBoxHost.Width - 1, searchBoxHost.Height - 1);
                // ОлНЙЪБЪЙгУжїЬтжїЩЋЃЈБпПђ1.5pxЃЉЃЌЮДОлНЙЪБЪЙгУБпПђЩЋЃЈБпПђ1pxЃЉ
                Color bc = searchFocus ? theme.Primary : theme.Border;
                using (GraphicsPath sp = GetRoundedPath(rect, 6)) // дВНЧАыОЖ6px
                {
                    using (SolidBrush br = new SolidBrush(theme.Surface))
                        e.Graphics.FillPath(br, sp); // ЬюГфБГОА
                    using (Pen pen = new Pen(bc, searchFocus ? 1.5f : 1f))
                        e.Graphics.DrawPath(pen, sp); // ЛцжЦБпПђ
                }
            };

            // ИќаТЫбЫїПђRegionЃЈвбЗЯЦњЃЌдВНЧаЇЙћЭЈЙ§PaintЪТМўЪЕЯжЃЉ
            void UpdateSearchBoxRegion()
            {
                // ВЛдйЪЙгУRegionВУМєЃЌБмУтВУЕєзгПиМўTextBox
                // дВНЧаЇЙћЭЈЙ§PaintЪТМўЛцжЦБпПђЪЕЯж
            }
            UpdateSearchBoxRegion();

            // ИќаТЗжзщЯТР­ПђRegionЃЈдВНЧВУМєЃЉ
            void UpdateCboGroupRegion()
            {
                if (cboGroupHost.Width > 0 && cboGroupHost.Height > 0)
                {
                    using (GraphicsPath path = GetRoundedPath(new Rectangle(0, 0, cboGroupHost.Width - 1, cboGroupHost.Height - 1), 6))
                    {
                        cboGroupHost.Region = new Region(path); // ВУМєЮЊдВНЧОиаЮ
                    }
                }
            }
            UpdateCboGroupRegion();

            searchPanelRef.Resize += (s, e) =>
            {
                int rightAreaWidth = cboGroupHost.Visible ? 328 : 15;
                int leftMargin = 98;
                searchBoxHost.Left = leftMargin;
                searchBoxHost.Width = Math.Max(100, searchPanelRef.ClientSize.Width - leftMargin - rightAreaWidth);
                txtSearch.Width = searchBoxHost.Width - 20;
                if (cboGroupHost.Visible)
                {
                    lblGroup.Left = searchPanelRef.ClientSize.Width - 298;
                    cboGroupHost.Left = searchPanelRef.ClientSize.Width - 158;
                    cboGroupHost.Width = 130;
                    cboGroupHost.Top = searchBoxHost.Top;
                }
                UpdateSearchBoxRegion();
                UpdateCboGroupRegion();
                searchBoxHost.Invalidate();
                cboGroupHost.Invalidate();
            };

            txtSearch.KeyDown += (s, e) =>
            {
                if (e.KeyCode == Keys.Enter)
                {
                    SearchChannels(txtSearch.Text);
                    e.SuppressKeyPress = true;
                }
            };

            ContextMenuStrip txtMenu = new ContextMenuStrip
            {
                Renderer = new ToolStripProfessionalRenderer(new MenuColorTable(IsDarkColor(theme.Bg))),
                Font = GetFont(SF(10f)),
                ShowImageMargin = true,
                BackColor = theme.Surface
            };
            ToolStripMenuItem miCut = new ToolStripMenuItem("МєЧа", null, (s, e) => txtSearch.Cut()) { ShortcutKeyDisplayString = "Ctrl+X" };
            ToolStripMenuItem miCopy = new ToolStripMenuItem("ИДжЦ", null, (s, e) => txtSearch.Copy()) { ShortcutKeyDisplayString = "Ctrl+C" };
            ToolStripMenuItem miPaste = new ToolStripMenuItem("еГЬљ", null, (s, e) =>
            {
                if (Clipboard.ContainsText())
                {
                    if (txtSearch.Text == "ЪфШыЫбЫїФкШнЃЌАДЯТЛиГЕМќЫбЫї")
                    {
                        txtSearch.Text = "";
                        txtSearch.ForeColor = theme.TextPrimary;
                    }
                    txtSearch.Paste();
                }
            })
            { ShortcutKeyDisplayString = "Ctrl+V" };
            ToolStripMenuItem miClear = new ToolStripMenuItem("ЧхПе", null, (s, e) =>
            {
                txtSearch.Clear();
                txtSearch.ForeColor = theme.TextSecondary;
            });
            txtMenu.Items.AddRange(new ToolStripItem[] { miCut, miCopy, miPaste, new ToolStripSeparator(), miClear });
            txtMenu.Opening += (s, e) =>
            {
                bool hasSel = txtSearch.SelectionLength > 0;
                bool canRead = !string.IsNullOrEmpty(txtSearch.Text) && txtSearch.Text != "ЪфШыЫбЫїФкШнЃЌАДЯТЛиГЕМќЫбЫї";
                miCut.Enabled = hasSel && !txtSearch.ReadOnly;
                miCopy.Enabled = hasSel;
                miPaste.Enabled = Clipboard.ContainsText() && !txtSearch.ReadOnly;
                miClear.Enabled = canRead;
            };
            txtSearch.ContextMenuStrip = txtMenu;

            // ЫбЫїРИЕзВПЗжИєЯп
            Panel searchSep = new Panel
            {
                Dock = DockStyle.Bottom,
                Height = 1,
                BackColor = ColorBorder
            };
            searchPanelRef.Controls.Add(searchSep);

            // ---- зДЬЌРИ(Dock=Top,дкsearchPanelRefЩЯЗНAdd) вЉЭшаЮзД ----
            statusBarContainer = new Panel
            {
                Dock = DockStyle.Top,
                Height = SY(32),
                BackColor = theme.Bg,
                Padding = new Padding(SX(12), SY(4), SX(12), SY(4))
            };

            statusBarRef = new DoubleBufferedPanel
            {
                Dock = DockStyle.Fill,
                BackColor = IsDarkColor(theme.Bg) ? Color.FromArgb(60, 60, 70) : Color.FromArgb(200, 200, 210)
            };
            statusBarRef.Paint += (s, e) =>
            {
                if (progressBarWidth > 0)
                {
                    using (SolidBrush brush = new SolidBrush(Color.FromArgb(0, 180, 80)))
                    {
                        e.Graphics.FillRectangle(brush, 0, 0, progressBarWidth, statusBarRef.ClientSize.Height);
                    }
                }
            };

            progressBarWidth = 0;

            lblDetected = new Label
            {
                Text = "вбМьВт: 0/0",
                Font = GetFont(SF(9.5f)),
                ForeColor = theme.TextPrimary,
                AutoSize = true,
                BackColor = Color.Transparent
            };
            statusBarRef.Controls.Add(lblDetected);

            lblAvailable = new Label
            {
                Text = "ПЩгУ: 0",
                Font = GetFont(SF(9.5f)),
                ForeColor = theme.TextPrimary,
                AutoSize = true,
                BackColor = Color.Transparent
            };
            statusBarRef.Controls.Add(lblAvailable);

            lblProgressText = new Label
            {
                Text = "МьВтНјЖШ:",
                Font = GetFont(SF(9.5f)),
                ForeColor = theme.TextPrimary,
                AutoSize = true,
                BackColor = Color.Transparent
            };
            statusBarRef.Controls.Add(lblProgressText);

            lblPercent = new Label
            {
                Text = "0.00%",
                Font = GetFont(SF(10.5f), FontStyle.Bold),
                ForeColor = theme.Primary,
                AutoSize = true,
                BackColor = Color.Transparent
            };
            statusBarRef.Controls.Add(lblPercent);

            lblStreamInfo = new Label
            {
                Text = "",
                Font = GetFont(SF(8.5f)),
                ForeColor = theme.TextSecondary,
                AutoSize = true,
                BackColor = Color.Transparent,
