            this.Shown += (s, e) =>
            {
                CenterEmptyState();
                int rightAreaWidth = cboGroupHost != null && cboGroupHost.Visible ? 328 : 15;
                int leftMargin = 98;
                searchBoxHost.Left = leftMargin;
                searchBoxHost.Width = searchPanelRef.ClientSize.Width - leftMargin - rightAreaWidth;
