            ay += SY(34) + SY(6);
            // НтЮіСДНгАДХЅЃКЮоТлЪЧЗёПЩМћЖМеМгУПеМф
            // ВМОжЫЕУїЃКАДХЅИпЖШ SY(34)ЃЌгы tipBox МфОр SY(26)ЃЌШЗБЃ tipBox дк Y=160 ЮЛжУ
            if (btnParseLink != null)
            {
                btnParseLink.Visible = canShowParseLink;
                btnParseLink.Location = new Point(SX(12), ay);
                ay += SY(34) + SY(26); // АДХЅИпЖШ 34 + МфОр 26 = 60ЃЌЪЙ tipBox ЮЛгк Y=160
            }

            // ЬсЪОРИИњЫцАДХЅЮЛжУздЖЏЛЌЖЏВЙе§
