            {
                tipBox.Location = new Point(SX(12), ay); // tipBox ЮЛгк Y=160ЃЈдкНтЮіСДНгАДХЅЯТЗНЃЉ
            }
        }

        private void UpdateTipBoxSize()
        {
            if (tipBox == null) return;
            string tipText = "1. СаБэЮЛжУЃЌЕуЛїгвМќЗЂЯжИќЖрЙІФм\r\n2. ЫЋЛїУћГЦЃЌжиУќУћЃЌЫЋЛїСДНгЃЌаоИДжБВЅдДЁЃ\r\n3. ДђПЊЩшжУЗЂЯжИќЖрЙІФмЁЃ";
