            // ====== ВНжш1ЃКЪфШыдДЕижЗ ======
            // [ВМОжНсЙЙ] БъЧЉ(28px) Ёњ МфОр(12px) Ёњ ЪфШыПђ(44px) Ёњ МфОр(12px) Ёњ ЬсЪОРИ(68px)
            
            // ------ БъЧЉ ------
            int step1Top = TOP_PADDING;  // ВНжш1ФкШнЦ№ЪМЮЛжУЃЈОрВНжшжИЪОЦїЕзВП20pxЃЉ
            
            // [ВНжш1БъЧЉ] "жБВЅдДЕижЗ"ЃЌДјБиЬюаЧКХ
