                ForeColor = DarkText, // ЩюЩЋЮФзж
                Location = new Point(CONTENT_PAD, step1Top),  // зѓЖдЦыЃЌОрзѓВрБпОр32px
                AutoSize = true,      // здЖЏЕїећДѓаЁ
