            step1Panel.Controls.Add(lblStep1Hint);
            step1Panel.Controls.Add(lblStep1Star);

            // ------ ЪфШыПђ ------
            // ЪфШыПђЖЅВПЮЛжУ = БъЧЉИпЖШ + ПиМўМфОр
            int step1InputTop = step1Top + hint1H + CONTROL_GAP;  
            
            // [URLЪфШыПђ] гУгкЪфШыжБВЅдДЕижЗЃЌжЇГжБъзМURLЛђздЖЈвхЗЖЮЇИёЪН
            TextBox txtStep1Url = new TextBox
            {
                Location = new Point(CONTENT_PAD, step1InputTop),  // зѓЖдЦыЃЌОрзѓВрБпОр32px
                Width = DLG_W - CONTENT_PAD * 2,                   // ПэЖШ = ДАПкПэЖШ - зѓгвБпОр
                Height = INPUT_HEIGHT,                              // ЪфШыПђИпЖШ44px
                Font = URL_FONT,                                    // ЕШПэзжЬх9.5ptЃЈConsolasЃЉ
                BorderStyle = BorderStyle.None,                     // ЮоБпПђЃЈздЖЈвхЛцжЦдВНЧБпПђЃЉ
                BackColor = InputBg,                                // ЪфШыПђБГОАЩЋЃЈЧГЛв/ЩюЩЋSurfaceЃЉ
                Padding = new Padding(SX(8), SX(2), SX(8), SX(2))   // ФкБпОрЃЌЗРжЙЮФзжБЛБпПђНиЖЯ
            };
            // ЩшжУдВНЧТЗОЖЃЈАыОЖ6pxЃЉ
            txtStep1Url.Region = new Region(CreateRoundedRectPath(new Rectangle(0, 0, txtStep1Url.Width, txtStep1Url.Height), SX(6)));
            // здЖЈвхЛцжЦБпПђЃЈОлНЙЪБТЬЩЋИпССЃЌЮДОлНЙЪБЛвЩЋЃЉ
            txtStep1Url.Paint += (s, pe) =>
            {
                Color borderColor = txtStep1Url.Focused ? InputFocusBorder : Color.FromArgb(100, 100, 100);  // ЩюЛвЩЋБпПђЃЌЧГЩЋжїЬтЯТИќабФП
                using (Pen p = new Pen(borderColor, 2.5f))
                {
                    pe.Graphics.DrawPath(p, CreateRoundedRectPath(new Rectangle(0, 0, txtStep1Url.Width - 1, txtStep1Url.Height - 1), SX(6)));
                }
            };
            // ЩшжУгвМќВЫЕЅЃЈМєЧа/ИДжЦ/еГЬљ/ШЋбЁ/ЧхПеЃЉ
            txtStep1Url.ContextMenuStrip = CreateInputContextMenu(txtStep1Url);
            
            // [еМЮЛЗћбеЩЋ] ЬсЪОЮФзжбеЩЋЃЌМгЩювдЬсИпПЩЖСадЃЈЩюЩЋжїЬтЯТЩдССЃЌЧГЩЋжїЬтЯТЩдЩюЃЉ
            Color phColor = isDark ? Color.FromArgb(120, 125, 135) : Color.FromArgb(130, 133, 140);
            bool phStep1Active = true;
            // ЩшжУеМЮЛЗћЮФзжЃЈЬсЪОгУЛЇжЇГжЕФЪфШыИёЪНЃЉ
            txtStep1Url.Text = "ЧыЪфШыжБВЅдДЕижЗЃЌжЇГжБъзМURLЛђ{0001-0100}/[1-100]здЖЈвхЗЖЮЇЃЌвВПЩгУ{Ъ§зж}ЪжЖЏПђбЁЩњГЩЖЮ";
            txtStep1Url.ForeColor = phColor;
            // ЛёШЁНЙЕуЪБЧхГ§еМЮЛЗћЃЌЛжИДе§ГЃЮФзжбеЩЋ
            txtStep1Url.GotFocus += (s, e) =>
            {
                if (phStep1Active) { phStep1Active = false; txtStep1Url.Text = ""; txtStep1Url.ForeColor = DarkText; }
                txtStep1Url.Invalidate();
            };
            // ЪЇШЅНЙЕуЪБШчЙћЪфШыПђЮЊПеЃЌЛжИДеМЮЛЗћ
            txtStep1Url.LostFocus += (s, e) =>
            {
