            int numPanelW = SX(180);   // Ъ§зжУцАхПэЖШ180pxЃЈАќКЌМгМѕАДХЅКЭЪфШыПђЃЉ
            int step3Top = TOP_PADDING;     // ВНжш3ФкШнЦ№ЪМЮЛжУ
            
