            // ------ БъЧЉ ------
            // [Ц№ЪМЪ§зжБъЧЉ] "Ц№ЪМЪ§зж"ЃЌОгжаЖдЦы
            Label lblStep3From = new Label
            {
                Text = "Ц№ЪМЪ§зж",
