                ForeColor = DarkText,
                Location = new Point(pFromX, step3Top),
                AutoSize = false,
                Size = new Size(numPanelW, SY(28)),     // ПэЖШгыЪ§зжУцАхвЛжТЃЌИпЖШ28px
                TextAlign = ContentAlignment.MiddleCenter,  // ЮФзжОгжаЖдЦы
                BackColor = PanelBg
            };
            step3Panel.Controls.Add(lblStep3From);
            
            // [НсЪјЪ§зжБъЧЉ] "НсЪјЪ§зж"ЃЌОгжаЖдЦы
            Label lblStep3To = new Label
            {
                Text = "НсЪјЪ§зж",
                Font = LABEL_FONT,
                ForeColor = DarkText,
                Location = new Point(pToX, step3Top),
                AutoSize = false,
                Size = new Size(numPanelW, SY(28)),     // ПэЖШгыЪ§зжУцАхвЛжТЃЌИпЖШ28px
                TextAlign = ContentAlignment.MiddleCenter,  // ЮФзжОгжаЖдЦы
                BackColor = PanelBg
            };
            step3Panel.Controls.Add(lblStep3To);

            TextBox txtFrom = null, txtTo = null;
            Panel pnlTextOptions = null;
            CheckedListBox clstTextCandidates = null;
            List<string> selectedTextValues = null;

            // ====== Ъ§зжУцАхДДНЈЗНЗЈ ======
            // [ДДНЈЪ§зжУцАх] ДДНЈвЛИіАќКЌМѕКХАДХЅЁЂЪфШыПђЁЂМгКХАДХЅЕФЪ§зжбЁдёУцАх
            // ВЮЪ§: x - УцАхXЮЛжУ, initialVal - ГѕЪМЪ§жЕ, outTextBox - ЗЕЛиЕФЪфШыПђв§гУ
            Panel CreateNumPanel(int x, long initialVal, out TextBox outTextBox)
            {
                // [Ъ§зжУцАхШнЦї] АќКЌМгМѕАДХЅКЭЪфШыПђЕФУцАх
                Panel p = new Panel
                {
                    Location = new Point(x, 0),
                    Width = numPanelW,
                    Height = INPUT_HEIGHT,
                    BackColor = InputBg,
                    BorderStyle = BorderStyle.None
                };
                // ЩшжУдВНЧТЗОЖЃЈАыОЖ6pxЃЉ
                p.Region = new Region(CreateRoundedRectPath(new Rectangle(0, 0, numPanelW, INPUT_HEIGHT), SX(6)));
                // здЖЈвхЛцжЦБпПђЃЈЩюЛвЩЋЃЌдВНЧЃЉ
                p.Paint += (s, pe) =>
                {
                    Color borderColor = isDark ? Color.FromArgb(100, 105, 115) : Color.FromArgb(130, 135, 145);
                    using (Pen pen = new Pen(borderColor, 2.5f))
                    {
                        pe.Graphics.DrawPath(pen, CreateRoundedRectPath(new Rectangle(0, 0, numPanelW - 1, INPUT_HEIGHT - 1), SX(6)));
                    }
                };
                
                int btnW = INPUT_HEIGHT;  // МгМѕАДХЅПэЖШ = ЪфШыПђИпЖШЃЈе§ЗНаЮЃЉ
                
                // [МѕКХАДХЅ] ЕуЛїМѕЩйЪ§зж
                Button btnMinus = new Button
                {
                    Text = "?",
                    Size = new Size(btnW, INPUT_HEIGHT - 2),
                    Location = new Point(0, 0),
                    FlatStyle = FlatStyle.Flat,
                    BackColor = LightBtnBg,
                    ForeColor = DarkText,
                    Font = NUMPAD_BTN_FONT,  // 14ptМгДжзжЬх
                    Cursor = Cursors.Hand
                };
                btnMinus.FlatAppearance.BorderSize = 0;
                btnMinus.FlatAppearance.MouseOverBackColor = NumPadHover;   // аќЭЃЪББГОАЩЋБфЩю
                btnMinus.FlatAppearance.MouseDownBackColor = NumPadDown;   // АДЯТЪББГОАЩЋИќЩю
                
                // [Ъ§зжЪфШыПђ] ЯдЪОКЭЪфШыЕБЧАЪ§жЕ
                TextBox tb = new TextBox
                {
                    Text = initialVal.ToString(),
                    Location = new Point(btnW + 2, (INPUT_HEIGHT - 24) / 2),  // ДЙжБОгжа
                    Width = numPanelW - btnW * 2 - 6,                         // ПэЖШ = УцАхПэЖШ - СНИіАДХЅПэЖШ
                    Height = 24,
                    BorderStyle = BorderStyle.None,
                    Font = NUM_INPUT_FONT,     // 12ptзжЬхЃЌОгжаЯдЪО
                    ForeColor = DarkText,
                    BackColor = InputBg,
                    TextAlign = HorizontalAlignment.Center
                };
                // ЩшжУгвМќВЫЕЅЃЈМєЧа/ИДжЦ/еГЬљ/ШЋбЁ/ЧхПеЃЉ
                tb.ContextMenuStrip = CreateInputContextMenu(tb);
                
                // [МгКХАДХЅ] ЕуЛїдіМгЪ§зж
                Button btnPlus = new Button
                {
                    Text = "+",
                    Size = new Size(btnW, INPUT_HEIGHT - 2),
                    Location = new Point(numPanelW - btnW - SX(1), 0),  // гвВрЖдЦы
                    FlatStyle = FlatStyle.Flat,
                    BackColor = LightBtnBg,
                    ForeColor = DarkText,
                    Font = NUMPAD_BTN_FONT,  // 14ptМгДжзжЬх
                    Cursor = Cursors.Hand
                };
                btnPlus.FlatAppearance.BorderSize = 0;
                btnPlus.FlatAppearance.MouseOverBackColor = NumPadHover;   // аќЭЃЪББГОАЩЋБфЩю
                btnPlus.FlatAppearance.MouseDownBackColor = NumPadDown;   // АДЯТЪББГОАЩЋИќЩю

                // МѕКХАДХЅЕуЛїЪТМўЃКЪ§зжМѕ1ЃЈзюаЁжЕЮЊ0ЃЉ
                btnMinus.Click += (s, e) =>
                {
                    long v;
                    if (long.TryParse(tb.Text, out v) && v > 0) { v--; tb.Text = v.ToString(); }
                    else { tb.Text = "0"; }
                };
                
                // МгКХАДХЅЕуЛїЪТМўЃКЪ§зжМг1ЃЈзюДѓжЕЮЊ9999999999ЃЉ
                btnPlus.Click += (s, e) =>
                {
                    long v;
                    if (long.TryParse(tb.Text, out v) && v < 9999999999L) { v++; tb.Text = v.ToString(); }
                    else if (!long.TryParse(tb.Text, out v)) { tb.Text = "0"; }
                };
                
                // ЪфШыПђАДМќЪТМўЃКжЛдЪаэЪфШыЪ§зж
                tb.KeyPress += (s, e) =>
                {
                    if (!char.IsControl(e.KeyChar) && !char.IsDigit(e.KeyChar))
                        e.Handled = true;
                };

                p.Controls.Add(btnMinus);
                p.Controls.Add(tb);
                p.Controls.Add(btnPlus);
                outTextBox = tb;
                return p;
            }

            // ------ Ъ§зжУцАх ------
            int step3PanelTop = step3Top + SY(28) + CONTROL_GAP;  // БъЧЉИпЖШ28px + ПиМўМфОр12px
            
            Panel pFrom = CreateNumPanel(pFromX, fromVal, out txtFrom);
