        private void ShowSearchEngineDialog()
        {
            SearchMode mode;
            
            if (watchSearchWindow)
            {
                mode = SearchMode.WebView2;
            }
            else
            {
                mode = ShowModeSelectionDialog();
                
                if ((int)mode == -1)
                {
                    return;
                }
            }
            
            if (mode == SearchMode.WebView2)
            {
                if (!CheckWindowsVersionSupported())
                {
                    DarkMessageBox.Show("ФњЕФЯЕЭГАцБОЙ§ЕЭЃЌWebView2ашвЊWindows 10 1809ЛђИќИпАцБОЁЃНЋздЖЏЪЙгУфЏРРЦїФЃЪНДђПЊЁЃ", "ЯЕЭГАцБОВЛжЇГж", MessageBoxButtons.OK, MessageBoxIcon.Information);
                    mode = SearchMode.Browser;
                }
                else
                {
                    List<string> missingDeps = CheckRuntimeDependencies();
                    if (missingDeps.Count > 0)
                    {
                        string depList = string.Join("\n", missingDeps);
                        DialogResult confirm = DarkMessageBox.Show($"МьВтЕНШБЩйвдЯТдЫааПтвРРЕЃК\n{depList}\n\nЪЧЗёздЖЏЯТдиАВзАЃП", "ШБЩйдЫааПт", MessageBoxButtons.YesNo, MessageBoxIcon.Question);
                        if (confirm == DialogResult.Yes)
                        {
                            Form progressForm = CreateProgressForm("е§дкАВзАдЫааПтвРРЕ...");
                            progressForm.Show(this);
                            Application.DoEvents();

                            bool vcInstalled = InstallVcRuntime();
                            progressForm.Close();

                            if (!vcInstalled)
                            {
                                DarkMessageBox.Show("VC++дЫааЪБАВзАЪЇАмЃЌWebView2ПЩФмЮоЗЈе§ГЃЙЄзїЁЃНЋЪЙгУфЏРРЦїФЃЪНДђПЊЁЃ", "АВзАЪЇАм", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                                mode = SearchMode.Browser;
                            }
                        }
                        else
                        {
                            mode = SearchMode.Browser;
                        }
                    }

                    if (mode == SearchMode.WebView2 && !IsWebView2Supported())
                    {
                        DialogResult confirm = DarkMessageBox.Show("ЯЕЭГЮДАВзАWebView2дЫааПтЃЌЪЧЗёздЖЏЯТдиАВзАЃП", "ШБЩйWebView2дЫааПт", MessageBoxButtons.YesNo, MessageBoxIcon.Question);
                        if (confirm == DialogResult.Yes)
                        {
                            Form progressForm = CreateProgressForm("е§дкЯТдиВЂАВзАWebView2дЫааПтЃЌЧыЩдКђ...");
                            progressForm.Show(this);
                            Application.DoEvents();

                            bool installed = InstallWebView2Runtime();
                            progressForm.Close();

                            if (!installed)
                            {
                                DarkMessageBox.Show("WebView2дЫааПтАВзАЪЇАмЃЌНЋЪЙгУфЏРРЦїФЃЪНДђПЊ", "АВзАЪЇАм", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                                mode = SearchMode.Browser;
                            }
                        }
                        else
                        {
                            mode = SearchMode.Browser;
                        }
                    }
                }
            }

            if (mode == SearchMode.Browser)
            {
                ShowBrowserSearchDialog();
            }
            else
            {
                ShowWebView2SearchDialog();
            }
        }

        /// <summary>
        /// ДДНЈМђвзНјЖШЖдЛАПђЃЈЧсСПМЖЃЌНіЯдЪОЮФБОЬсЪОЃЉ
        /// гУгкАВзАдЫааПтЁЂWebView2ЕШКѓЬЈВйзїЪБЯдЪОЕШД§зДЬЌ
        /// </summary>
        /// <param name="message">ЯдЪОЕФЬсЪОЮФзж</param>
        /// <returns>НјЖШЖдЛАПђДАЬх</returns>
        private Form CreateProgressForm(string message)
        {
            // ========== беЩЋХфжУЃЈИљОнжїЬтздЖЏЧаЛЛЃЉ ==========
            bool isDark = theme.Name == "ЩюЩЋ";
            Color progressBg = isDark ? Color.FromArgb(46, 78, 126) : Color.White;      // ДАПкБГОАЩЋЃЈЩюЩЋЃКРЖЛвЩЋ / ЧГЩЋЃКДПАзЃЉ
            Color progressText = isDark ? Color.White : Color.FromArgb(51, 51, 51);     // ЮФзжбеЩЋ

            // ========== жїДАПкХфжУ ==========
            // [ЮЛжУ] ЪжЖЏЖЈЮЛЃЈгЩЕїгУЗНИКд№ОгжаЃЉ[ДѓаЁ] 400x120 [бљЪН] ЙЬЖЈЖдЛАПђ
            Form progressForm = new Form
            {
                Text = "АВзАНјЖШ",                         // ДАПкБъЬт
                StartPosition = FormStartPosition.Manual,   // ЪжЖЏЖЈЮЛЃЈЕїгУЗНИКд№ОгжагкжїДАПкЃЉ
                FormBorderStyle = FormBorderStyle.FixedDialog,  // ЙЬЖЈЖдЛАПђбљЪНЃЌНћжЙЕїећДѓаЁ
                MaximizeBox = false,                       // НћгУзюДѓЛЏАДХЅ
                MinimizeBox = false,                       // НћгУзюаЁЛЏАДХЅ
                ShowInTaskbar = false,                     // ВЛдкШЮЮёРИЯдЪО
                ClientSize = new Size(SX(400), SY(120)),    // ДАПкДѓаЁЃЈПэ400pxЃЌИп120pxЃЌDPIЪЪХфЃЉ
                BackColor = progressBg                     // ДАПкБГОАЩЋ
            };
            SetFormDarkModeTitleBar(progressForm, isDark);  // гІгУЩюЩЋБъЬтРИ

            // ========== ЬсЪОБъЧЉ ==========
            // [ЮЛжУ] (20, 40) [ДѓаЁ] 360x24 [зжЬх] YaHei 10pt
            Label lblProgress = new Label
            {
                Text = message,
                Font = GetFont(10f),
                ForeColor = progressText,
                Location = new Point(SX(20), SY(40)),
                Size = new Size(SX(360), SY(24))
            };
            progressForm.Controls.Add(lblProgress);

            return progressForm;
        }

        /// <summary>
        /// ЯдЪОфЏРРЦїЫбЫїЖдЛАПђЃЈЙцдђЫбЫїЙІФмЃЉ
        /// дЪаэгУЛЇбЁдёЫбЫїЙцдђКЭЫбЫїв§ЧцЃЌдкфЏРРЦїжаДђПЊЫбЫїНсЙћ
        /// </summary>
        private void ShowBrowserSearchDialog()
        {
            // ========== беЩЋХфжУЃЈИљОнжїЬтздЖЏЧаЛЛЃЉ ==========
            bool isDark = theme.Name == "ЩюЩЋ";
            Color LightBlueBg = Color.FromArgb(46, 78, 126);      // ЩюЩЋжїЬтЧГРЖБГОА
            Color PanelBg = isDark ? LightBlueBg : Color.White;   // УцАхБГОАЩЋЃЈЩюЩЋЃКЧГРЖ / ЧГЩЋЃКДПАзЃЉ
            Color SurfaceBg = isDark ? Color.FromArgb(36, 62, 100) : Color.White; // БэУцБГОАЩЋЃЈБШУцАхТдЩю/ЭЌЩЋЃЉ
            Color TextPrimary = isDark ? Color.White : Color.FromArgb(51, 51, 51);      // жїЮФзжЩЋ
            Color TextSecondary = isDark ? Color.FromArgb(200, 220, 240) : Color.FromArgb(153, 153, 153); // ДЮвЊЮФзжЩЋ
            Color BorderColor = isDark ? Color.FromArgb(60, 100, 150) : Color.FromArgb(200, 203, 210);  // БпПђЩЋ
            Color PrimaryColor = isDark ? Color.FromArgb(100, 150, 220) : theme.Primary; // жїЩЋЕїЃЈРЖЩЋЯЕЃЉ
            Color HoverBg = isDark ? Color.FromArgb(50, 85, 135) : Color.FromArgb(248, 249, 250); // аќЭЃБГОАЩЋ

            // БЃДцжїДАПкзДЬЌЃЈгУгкЙиБеЖдЛАПђКѓЛжИДЃЉ
            FormWindowState originalState = this.WindowState;
            Rectangle originalBounds = this.Bounds;

            // ========== жїДАПкХфжУ ==========
            // [БъЬт] ЙцдђЫбЫї [ДѓаЁ] 900x550 [бљЪН] ПЩЕїећДѓаЁ [ЮЛжУ] ОгжагкжїДАПк
            Form dlg = new Form
            {
                Text = "ЙцдђЫбЫї",                    // ДАПкБъЬт
                StartPosition = FormStartPosition.Manual,  // ЪжЖЏЖЈЮЛ
                FormBorderStyle = FormBorderStyle.Sizable, // ПЩЕїећДѓаЁ
                MaximizeBox = true,                   // ЦєгУзюДѓЛЏАДХЅ
                MinimizeBox = true,                   // ЦєгУзюаЁЛЏАДХЅ
                ShowInTaskbar = true,                 // дкШЮЮёРИЯдЪО
                BackColor = PanelBg,                  // ДАПкБГОАЩЋ
                ClientSize = new Size(SX(900), SY(550)),  // ДАПкДѓаЁЃЈ900x550pxЃЌDPIЪЪХфЃЉ
                KeyPreview = true                     // дЄРРМќХЬЪТМў
            };
            SetFormDarkModeTitleBar(dlg, isDark);     // гІгУЩюЩЋБъЬтРИ
            CenterForm(dlg, this);                    // ОгжагкжїДАПк

            // вўВижїДАПкЃЌЙиБеЖдЛАПђКѓЛжИД
            this.Hide();
            dlg.Closed += (s, e) =>
            {
                this.Show();                         // ЯдЪОжїДАПк
                this.WindowState = originalState;    // ЛжИДДАПкзДЬЌ
                if (originalState != FormWindowState.Maximized)
                {
                    this.Bounds = originalBounds;    // ЛжИДДАПкЮЛжУКЭДѓаЁ
                }
                this.Activate();                     // МЄЛюжїДАПк
                this.Refresh();                      // ЫЂаТНчУц
            };

            // ========== ЖЅВПРИЃЈБъЬт+ЙцдђбЁдё+ЫбЫїАДХЅЃЉ ==========
            // [ЮЛжУ] ЖЅВПDock [ИпЖШ] 60px [БГОА] БэУцБГОАЩЋ
            Panel topBar = new Panel
            {
                Dock = DockStyle.Top,
                Height = SY(60),
                BackColor = SurfaceBg
            };
            dlg.Controls.Add(topBar);

            // ========== жїФкШнУцАхЃЈЫбЫїв§ЧцСаБэЃЉ ==========
            // [ЮЛжУ] ЬюГфЪЃгрПеМф [ФкБпОр] 20px [БГОА] УцАхБГОАЩЋ
            Panel mainPanel = new Panel
            {
                Dock = DockStyle.Fill,
                BackColor = PanelBg,
                Padding = new Padding(SX(20))
            };
            dlg.Controls.Add(mainPanel);

            // ========== БъЬтБъЧЉ ==========
            // [ЮЛжУ] (16, 0) [ДѓаЁ] 200x48 [зжЬх] YaHei 12pt Bold [ЖдЦы] зѓОгжа
            Label lblTitle = new Label
            {
                Text = "ЙцдђЫбЫї",
                Font = GetFont(12f, FontStyle.Bold),  // зжЬхЃЈ12pt Bold * DPIЫѕЗХЃЉ
                ForeColor = TextPrimary,
                Location = new Point(SX(16), 0),
                Size = new Size(SX(200), SY(48)),
                TextAlign = ContentAlignment.MiddleLeft,
                BackColor = Color.Transparent
            };
            topBar.Controls.Add(lblTitle);

            // ========== ЫбЫїЙцдђЯТР­Пђ ==========
            // [ЮЛжУ] (220, 14) [ДѓаЁ] 120x32 [бЁЯю] жЧЛлзРУц/жЧЛлЙтбИ/ЛЊЪгУРДя [ФЌШЯ] жЧЛлзРУц
            ComboBox cboSearchRule = new ComboBox
            {
                DropDownStyle = ComboBoxStyle.DropDownList, // жЛЖСЯТР­СаБэ
                Size = new Size(SX(120), SY(32)),
                FlatStyle = FlatStyle.Flat,
                BackColor = isDark ? Color.FromArgb(30, 50, 80) : Color.White, // БГОАЩЋ
                ForeColor = TextPrimary,
                Font = GetFont(10f),                        // зжЬхЃЈ10pt * DPIЫѕЗХЃЉ
                Cursor = Cursors.Hand,
                Location = new Point(SX(220), SY(14))
            };
            cboSearchRule.Items.AddRange(new object[] { "жЧЛлзРУц", "жЧЛлЙтбИ", "ЛЊЪгУРДя" });
            cboSearchRule.SelectedIndex = 0;               // ФЌШЯбЁжаЕквЛИібЁЯю
            // здЖЈвхЛцжЦБпПђ
            cboSearchRule.Paint += (s, e) =>
            {
                ComboBox cb = (ComboBox)s;
                using (Pen pen = new Pen(BorderColor))
                    e.Graphics.DrawRectangle(pen, 0, 0, cb.Width - 1, cb.Height - 1);
            };
            topBar.Controls.Add(cboSearchRule);

            // ========== ЫбЫїЙцдђгГЩфБэ ==========
            // МќЃКЙцдђУћГЦЃЌжЕЃКFOFAЫбЫїЙцдђ
            var searchRules = new Dictionary<string, string>
            {
                {"жЧЛлзРУц", "body=\"/iptv/live/zh_cn.js\""},
                {"жЧЛлЙтбИ", "body=\"ZHGXTV\""},
                {"ЛЊЪгУРДя", "body=\"ЛЊЪгУРДя\""}
            };

            // ========== ЫбЫїв§ЧцгГЩфБэ ==========
            // МќЃКЫбЫїв§ЧцУћГЦЃЌжЕЃКЫбЫїв§ЧцURL
            var searchEngines = new Dictionary<string, string>
            {
                {"FOFA", "https://fofa.info/"},
                {"Quake", "https://quake.360.net/"},
                {"Hunter", "https://hunter.qianxin.com/"},
                {"ZoomEye", "https://www.zoomeye.org/"},
                {"Shodan", "https://www.shodan.io/"},
                {"Censys", "https://search.censys.io/"}
            };

            string selectedEngine = "FOFA"; // ФЌШЯбЁжаFOFA

            // ========== ДђПЊЫбЫїАДХЅ ==========
            // [ЮЛжУ] (780, 14) [ДѓаЁ] 100x32 [зжЬх] YaHei 10pt Bold [дВНЧ] 6px [беЩЋ] жїЩЋЕїБГОА+АзЩЋЮФзж
            Button btnSearch = new Button
            {
                Text = "ДђПЊЫбЫї",
                Size = new Size(SX(100), SY(32)),
                FlatStyle = FlatStyle.Flat,
                BackColor = PrimaryColor,
                ForeColor = Color.White,
                Font = GetFont(10f, FontStyle.Bold),
                Cursor = Cursors.Hand,
                Location = new Point(SX(780), SY(14)),
                Visible = showSearchButton
            };
            btnSearch.FlatAppearance.BorderSize = 0;
            btnSearch.FlatAppearance.MouseOverBackColor = Color.FromArgb(
                Math.Min(255, PrimaryColor.R + 20),
                Math.Min(255, PrimaryColor.G + 20),
                Math.Min(255, PrimaryColor.B + 20)); // аќЭЃЪБбеЩЋБфСС
            StyleRoundButton(btnSearch, 6, null, 0, "dynamic"); // ЩшжУдВНЧЃЈ6pxЃЉ
            btnSearch.Click += (s, e) =>
            {
                // ЛёШЁбЁжаЕФЙцдђКЭв§ЧцЃЌЙЙНЈЫбЫїURLВЂдкфЏРРЦїжаДђПЊ
                string ruleName = cboSearchRule.SelectedItem?.ToString() ?? "жЧЛлзРУц";
                string searchRule = searchRules.ContainsKey(ruleName) ? searchRules[ruleName] : searchRules["жЧЛлзРУц"];
                string baseUrl = searchEngines.ContainsKey(selectedEngine) ? searchEngines[selectedEngine] : searchEngines["FOFA"];
                string url = baseUrl + "result?qbase64=" + Convert.ToBase64String(System.Text.Encoding.UTF8.GetBytes(searchRule));
                try
                {
                    System.Diagnostics.Process.Start(new System.Diagnostics.ProcessStartInfo(url) { UseShellExecute = true });
                }
                catch { }
            };
            topBar.Controls.Add(btnSearch);
            btnSearchRef = btnSearch;

            // ЖЅВПРИЕзВПБпПђЛцжЦ
            topBar.Paint += (s, e) =>
            {
                Panel p = (Panel)s;
                using (Pen pen = new Pen(BorderColor))
                    e.Graphics.DrawLine(pen, 0, SY(47), p.Width, SY(47)); // дкY=47ДІЛцжЦЗжИєЯпЃЈDPIЪЪХфЃЉ
            };

            // ========== ЫбЫїв§ЧцСаБэУцАх ==========
            // [ЮЛжУ] (20, 80) [ДѓаЁ] 860x420 [БГОА] БэУцБГОАЩЋ [БпПђ] ЙЬЖЈЕЅБпПђ
            Panel listPanel = new Panel
            {
                Location = new Point(SX(20), SY(80)),
                Size = new Size(SX(860), SY(420)),
                BackColor = SurfaceBg,
                BorderStyle = BorderStyle.FixedSingle
            };
            mainPanel.Controls.Add(listPanel);

            Color hoverColor = isDark ? Color.FromArgb(50, 85, 135) : Color.FromArgb(240, 245, 250); // СаБэЯюаќЭЃЩЋ

            // ========== ЖЏЬЌЩњГЩЫбЫїв§ЧцСаБэЯю ==========
            // УПИіСаБэЯюАќКЌЃКЕЅбЁАДХЅ(в§ЧцУћГЦ) + URLБъЧЉ + ЗУЮЪАДХЅ
            // СаБэЯюИпЖШ55pxЃЌМфОр5pxЃЈРлМЦ60pxЃЉ
            int y = 10;
            foreach (var engine in searchEngines)
            {
                // СаБэЯюШнЦїЃЈДјаќЭЃИпССЃЉ
                Panel itemPanel = new Panel
                {
                    Location = new Point(SX(10), y),
                    Size = new Size(SX(840), SY(55)),
                    BackColor = Color.Transparent
                };
                listPanel.Controls.Add(itemPanel);

                // аќЭЃаЇЙћЃКЪѓБъНјШыЪБЯдЪОИпССБГОА
                itemPanel.MouseEnter += (s, e) =>
                {
                    itemPanel.BackColor = hoverColor;
                };
                itemPanel.MouseLeave += (s, e) =>
                {
                    itemPanel.BackColor = Color.Transparent;
                };

                // ЫбЫїв§ЧцЕЅбЁАДХЅ
                RadioButton rbEngine = new RadioButton
                {
                    Text = engine.Key,
                    Size = new Size(SX(100), SY(36)),
                    Location = new Point(0, SY(7)),
                    FlatStyle = FlatStyle.Flat,
                    BackColor = Color.Transparent,
                    ForeColor = isDark ? Color.White : Color.FromArgb(51, 51, 51),
                    Font = GetFont(10f, FontStyle.Bold), // зжЬхЃЈ10pt Bold * DPIЫѕЗХЃЉ
                    Cursor = Cursors.Hand,
                    Checked = engine.Key == selectedEngine // ФЌШЯбЁжаFOFA
                };
                rbEngine.CheckedChanged += (s, e) =>
                {
                    if (rbEngine.Checked)
                    {
                        selectedEngine = engine.Key; // ИќаТбЁжаЕФЫбЫїв§Чц
                    }
                };
                itemPanel.Controls.Add(rbEngine);

                // ЫбЫїв§ЧцURLБъЧЉ
                Label lblUrl = new Label
                {
                    Text = engine.Value,
                    Size = new Size(SX(630), SY(36)),
                    Location = new Point(SX(130), SY(10)),
                    Font = GetFont(10f),              // зжЬхЃЈ10pt * DPIЫѕЗХЃЉ
                    ForeColor = TextSecondary,       // ДЮвЊЮФзжЩЋЃЈЛвЩЋЃЉ
                    TextAlign = ContentAlignment.MiddleLeft
                };
                itemPanel.Controls.Add(lblUrl);

                // ЗУЮЪАДХЅ
                Button btnGo = new Button
                {
                    Text = "ЗУЮЪ",
                    Size = new Size(SX(70), SY(36)),
                    Location = new Point(SX(760), SY(10)),
                    FlatStyle = FlatStyle.Flat,
                    BackColor = PrimaryColor,         // жїЩЋЕїБГОА
                    ForeColor = Color.White,          // АзЩЋЮФзж
                    Font = GetFont(9f, FontStyle.Bold), // зжЬхЃЈ9pt Bold * DPIЫѕЗХЃЉ
                    Cursor = Cursors.Hand
                };
                btnGo.FlatAppearance.BorderSize = 0;
                btnGo.FlatAppearance.MouseOverBackColor = Color.FromArgb(
                    Math.Min(255, PrimaryColor.R + 20),
                    Math.Min(255, PrimaryColor.G + 20),
                    Math.Min(255, PrimaryColor.B + 20)); // аќЭЃЪБбеЩЋБфСС
                StyleRoundButton(btnGo, 6, null, 0, "dynamic"); // ЩшжУдВНЧЃЈ6pxЃЉ
                btnGo.Click += (s, e) =>
                {
                    // дкфЏРРЦїжаДђПЊЫбЫїв§ЧцжївГ
                    try
                    {
                        System.Diagnostics.Process.Start(new System.Diagnostics.ProcessStartInfo(engine.Value) { UseShellExecute = true });
                    }
                    catch { }
                };
                itemPanel.Controls.Add(btnGo);

                y += 60; // ЯТвЛИіСаБэЯюYзјБъЃЈ55pxИпЖШ + 5pxМфОрЃЉ
            }

            dlg.ShowDialog(this); // ЯдЪОЖдЛАПђЃЈФЃЬЌЃЉ
        }

        private void ShowWebView2SearchDialog()
        {
            try
            {
                bool isDark = theme.Name == "ЩюЩЋ";
                Color LightBlueBg = Color.FromArgb(46, 78, 126);
                Color PanelBg = isDark ? LightBlueBg : Color.White;
                Color SurfaceBg = isDark ? Color.FromArgb(36, 62, 100) : Color.White;
                Color TextPrimary = isDark ? Color.White : Color.FromArgb(51, 51, 51);
                Color TextSecondary = isDark ? Color.FromArgb(200, 220, 240) : Color.FromArgb(153, 153, 153);
                Color BorderColor = isDark ? Color.FromArgb(60, 100, 150) : Color.FromArgb(200, 203, 210);
                Color PrimaryColor = isDark ? Color.FromArgb(100, 150, 220) : theme.Primary;
                Color HoverBg = isDark ? Color.FromArgb(50, 85, 135) : Color.FromArgb(248, 249, 250);

                int NAV_BAR_H = 36;

                FormWindowState originalState = this.WindowState;
                Rectangle originalBounds = this.Bounds;

                Form dlg = new Form
                {
                    Text = "",
                    StartPosition = FormStartPosition.CenterScreen,
                    FormBorderStyle = FormBorderStyle.Sizable,
                    MaximizeBox = true,
                    MinimizeBox = true,
                    ShowInTaskbar = true,
                    BackColor = PanelBg,
                    KeyPreview = true,
                    ClientSize = this.ClientSize,
                    Icon = null
                };
                SetFormDarkModeTitleBar(dlg, isDark);
                CenterForm(dlg, this);

                this.Hide();

                bool wasMaximized = false;
                Action SetRoundedRegion = () =>
                {
                    if (dlg.WindowState == FormWindowState.Maximized)
                    {
                        dlg.Region = null;
                        return;
                    }
                    int radius = 12;
                    using (System.Drawing.Drawing2D.GraphicsPath path = new System.Drawing.Drawing2D.GraphicsPath())
                    {
                        Rectangle rect = new Rectangle(0, 0, dlg.Width, dlg.Height);
                        path.AddArc(rect.X, rect.Y, radius, radius, 180, 90);
                        path.AddArc(rect.X + rect.Width - radius, rect.Y, radius, radius, 270, 90);
                        path.AddArc(rect.X + rect.Width - radius, rect.Y + rect.Height - radius, radius, radius, 0, 90);
                        path.AddArc(rect.X, rect.Y + rect.Height - radius, radius, radius, 90, 90);
                        path.CloseAllFigures();
                        dlg.Region = new Region(path);
                    }
                };
                dlg.Resize += (s, e) =>
                {
                    if (dlg.WindowState == FormWindowState.Maximized)
                    {
                        wasMaximized = true;
                    }
                    else if (dlg.WindowState == FormWindowState.Normal && wasMaximized)
                    {
                        int screenWidth = Screen.PrimaryScreen.WorkingArea.Width;
                        int screenHeight = Screen.PrimaryScreen.WorkingArea.Height;
                        int x = (screenWidth - dlg.Width) / 2;
                        int y = (screenHeight - dlg.Height) / 2;
                        dlg.Location = new System.Drawing.Point(x, y);
                        wasMaximized = false;
                    }
                    SetRoundedRegion();
                };
                SetRoundedRegion();

                dlg.Closed += (s, e) =>
                {
                    this.Show();
                    this.WindowState = originalState;
                    if (originalState != FormWindowState.Maximized)
                    {
                        this.Bounds = originalBounds;
                        this.CenterToScreen();
                    }
                    this.Activate();
                    this.Refresh();
                };

                Panel navPanel = new Panel
                {
                    Height = NAV_BAR_H,
                    BackColor = SurfaceBg,
                    Padding = new Padding(8, 0, 8, 0),
                    Top = -NAV_BAR_H,
                    Width = dlg.ClientSize.Width
                };
                dlg.Controls.Add(navPanel);

                int BORDER_WIDTH = 8;
                int STATUS_BAR_H = 28;

                Panel leftBorder = new Panel
                {
                    Width = BORDER_WIDTH,
                    BackColor = BorderColor,
                    Dock = DockStyle.Left
                };
                dlg.Controls.Add(leftBorder);

                Panel rightBorder = new Panel
                {
                    Width = BORDER_WIDTH,
                    BackColor = BorderColor,
                    Dock = DockStyle.Right
                };
                dlg.Controls.Add(rightBorder);

                Panel statusBar = new Panel
                {
                    Height = STATUS_BAR_H,
                    BackColor = SurfaceBg,
                    Dock = DockStyle.Bottom,
                    Padding = new Padding(8, 0, 8, 0)
                };

                Label lblStatusUrl = new Label
                {
                    Text = "",
                    Font = GetFont(9f),
                    ForeColor = TextSecondary,
                    BackColor = SurfaceBg,
                    Size = new Size(400, STATUS_BAR_H),
                    Location = new Point(8, 0),
                    TextAlign = ContentAlignment.MiddleLeft,
                    AutoSize = false
                };

                Label lblStatusIp = new Label
                {
                    Text = "IPЬсШЁ: Йи",
                    Font = GetFont(9f),
                    ForeColor = TextSecondary,
                    BackColor = SurfaceBg,
                    Size = new Size(120, STATUS_BAR_H),
                    Location = new Point(dlg.ClientSize.Width - BORDER_WIDTH * 2 - 130, 0),
                    TextAlign = ContentAlignment.MiddleRight,
                    AutoSize = false
                };

                Label lblStatusEngine = new Label
                {
                    Text = "ЫбЫїв§Чц: FOFA",
                    Font = GetFont(9f),
                    ForeColor = TextSecondary,
                    BackColor = SurfaceBg,
                    Size = new Size(150, STATUS_BAR_H),
                    Location = new Point(dlg.ClientSize.Width - BORDER_WIDTH * 2 - 280, 0),
                    TextAlign = ContentAlignment.MiddleRight,
                    AutoSize = false
                };

                statusBar.Controls.Add(lblStatusUrl);
                statusBar.Controls.Add(lblStatusIp);
                statusBar.Controls.Add(lblStatusEngine);
                dlg.Controls.Add(statusBar);

                webViewStatusUrl = lblStatusUrl;

                System.Windows.Forms.Timer navTimer = new System.Windows.Forms.Timer();
                navTimer.Interval = 100;

                bool isNavVisible = false;
                bool isDropdownOpen = false;
                int hideCountdown = 0;

                Action ShowNav = () =>
                {
                    if (!isNavVisible)
                    {
                        navPanel.Top = 0;
                        isNavVisible = true;
                    }
                    hideCountdown = 0;
                };

                Action HideNav = () =>
                {
                    if (isNavVisible)
                    {
                        navPanel.Top = -NAV_BAR_H;
                        isNavVisible = false;
                    }
                };

                navTimer.Tick += (s, e) =>
                {
                    if (isDropdownOpen)
                    {
                        hideCountdown = 0;
                        return;
                    }

