                void Log(string msg)
                {
                    if (txtLog.IsDisposed) return;
                    if (txtLog.InvokeRequired)
                        txtLog.BeginInvoke(new Action(() =>
                        {
                            txtLog.AppendText($"{DateTime.Now.ToString("HH:mm:ss")} | {msg}\r\n");
                            txtLog.ScrollToCaret();
                        }));
                    else
                    {
                        txtLog.AppendText($"{DateTime.Now.ToString("HH:mm:ss")} | {msg}\r\n");
                        txtLog.ScrollToCaret();
                    }
                }

